// Auto-explore feature for automatic fractal discovery.
// Provides functionality for automatically exploring fractal boundaries
// and discovering visually interesting areas.

export 'auto_explore_service.dart';
export 'auto_explore_controls.dart';
export 'auto_explore_control_status.dart';

import 'package:flutter/material.dart';
import 'package:flutter/semantics.dart';
import 'package:flutter_fractals/core/modules/module_registry.dart';
import 'package:flutter_fractals/features/auto_explore/auto_explore_controls.dart';
import 'package:flutter_fractals/features/auto_explore/auto_explore_service.dart';
import 'package:flutter_fractals/features/renderer/providers/fractal_provider.dart';
import 'package:flutter_test/flutter_test.dart';
import 'package:provider/provider.dart';

void main() {
  group('AutoExploreSettingsSheet', () {
    testWidgets('shows resume affordance while auto-explore is yielded',
        (tester) async {
      final controller = FractalController(ModuleRegistry());
      final service = AutoExploreService(controller: controller);
      addTearDown(service.dispose);
      addTearDown(controller.dispose);

      service.start();
      service.onUserInteractionStart();

      await tester.pumpWidget(
        MaterialApp(
          home: ChangeNotifierProvider<AutoExploreService>.value(
            value: service,
            child: const Scaffold(
              body: AutoExploreSettingsSheet(),
            ),
          ),
        ),
      );

      expect(find.text('Auto-pilot paused (user correction)'), findsOneWidget);
      expect(find.text('Resume'), findsOneWidget);
      expect(find.text('Play'), findsNothing);
      expect(find.text('Pause'), findsNothing);
    });
  });

  group('AutoExploreButton semantics', () {
    testWidgets('exposes tap action for assistive activation', (tester) async {
      final semanticsHandle = tester.ensureSemantics();
      final controller = FractalController(ModuleRegistry());
      final service = AutoExploreService(controller: controller);
      addTearDown(service.dispose);
      addTearDown(controller.dispose);

      await tester.pumpWidget(
        MaterialApp(
          home: ChangeNotifierProvider<AutoExploreService?>.value(
            value: service,
            child: const Scaffold(
              body: AutoExploreButton(),
            ),
          ),
        ),
      );
      await tester.pumpAndSettle();

      final data = _semanticsDataForLabel(tester, 'Start auto-explore');
      expect(data, isNotNull);
      expect(data!.hasAction(SemanticsAction.tap), isTrue);
      // ignore: deprecated_member_use
      expect(data.hasFlag(SemanticsFlag.isButton), isTrue);

      semanticsHandle.dispose();
    });

    testWidgets('labels user-correction yield without claiming active motion',
        (tester) async {
      final semanticsHandle = tester.ensureSemantics();
      final controller = FractalController(ModuleRegistry());
      final service = AutoExploreService(controller: controller);
      addTearDown(service.dispose);
      addTearDown(controller.dispose);

      service.start();
      service.onUserInteractionStart();

      await tester.pumpWidget(
        MaterialApp(
          home: ChangeNotifierProvider<AutoExploreService?>.value(
            value: service,
            child: const Scaffold(
              body: AutoExploreButton(),
            ),
          ),
        ),
      );
      await tester.pumpAndSettle();

      final yieldedData = _semanticsDataForLabel(tester, 'Auto-pilot paused');
      final activeData = _semanticsDataForLabel(tester, 'Pause auto-explore');

      expect(yieldedData, isNotNull);
      expect(yieldedData!.hasAction(SemanticsAction.tap), isTrue);
      expect(activeData, isNull);

      semanticsHandle.dispose();
    });

    testWidgets('tap resumes from user-correction yield instead of pausing',
        (tester) async {
      final controller = FractalController(ModuleRegistry());
      final service = AutoExploreService(controller: controller);
      addTearDown(service.dispose);
      addTearDown(controller.dispose);

      service.start();
      service.onUserInteractionStart();

      await tester.pumpWidget(
        MaterialApp(
          home: ChangeNotifierProvider<AutoExploreService?>.value(
            value: service,
            child: const Scaffold(
              body: AutoExploreButton(),
            ),
          ),
        ),
      );
      await tester.pumpAndSettle();

      expect(service.pausedByUserCorrection, isTrue);
      expect(service.isPaused, isFalse);

      await tester.tap(find.byType(AutoExploreButton));
      await tester.pump();

      expect(service.isExploring, isTrue);
      expect(service.isPaused, isFalse);
      expect(service.pausedByUserCorrection, isFalse);

      service.stop();
      await tester.pump();
    });
  });
}

SemanticsData? _semanticsDataForLabel(WidgetTester tester, String label) {
  // ignore: deprecated_member_use
  final root = tester.binding.pipelineOwner.semanticsOwner?.rootSemanticsNode;
  SemanticsData? result;

  bool visit(SemanticsNode node) {
    final data = node.getSemanticsData();
    if (data.label == label) {
      result = data;
      return false;
    }
    node.visitChildren(visit);
    return result == null;
  }

  if (root != null) visit(root);
  return result;
}

import 'package:flutter/foundation.dart';
import 'package:vector_math/vector_math.dart';
import 'package:flutter_fractals/core/models/fractal_view_state.dart';
import 'package:flutter_fractals/features/history/history_location.dart';

/// Represents a visited location in fractal exploration history.
///
/// Each entry captures the complete state needed to restore a viewpoint:
/// - The fractal module (type) being viewed
/// - The view state (pan, zoom, rotation)
/// - The fractal parameters at that time
/// - Optional metadata like name (for favorites) and timestamp
///
/// {@category Models}
@immutable
class HistoryEntry {
  /// Unique identifier for this history entry.
  final String id;

  /// The fractal module ID (e.g., 'mandelbrot', 'julia').
  final String moduleId;

  /// The view state (pan, zoom, rotation) at this location.
  final FractalViewState view;

  /// The fractal parameters at this location.
  final Map<String, Object> params;

  /// When this location was visited.
  final DateTime visitedAt;

  /// Optional user-defined name for favorites.
  ///
  /// If non-null, this entry is considered a favorite.
  final String? name;

  /// Whether this entry is marked as a favorite.
  bool get isFavorite => name != null;

  /// Creates a new [HistoryEntry].
  ///
  /// The supplied view vectors and parameter collections are snapshotted so a
  /// history entry remains replayable even when callers mutate their originals.
  HistoryEntry({
    required this.id,
    required this.moduleId,
    required FractalViewState view,
    required Map<String, Object> params,
    required this.visitedAt,
    this.name,
  })  : view = snapshotHistoryView(view),
        params = snapshotHistoryParams(params);

  /// Creates a history entry from the current fractal state.
  factory HistoryEntry.fromState({
    required String moduleId,
    required FractalViewState view,
    required Map<String, Object> params,
    String? name,
  }) {
    return HistoryEntry(
      id: DateTime.now().microsecondsSinceEpoch.toString(),
      moduleId: moduleId,
      view: view,
      params: params,
      visitedAt: DateTime.now(),
      name: name,
    );
  }

  /// Creates a copy with the given fields replaced.
  HistoryEntry copyWith({
    String? id,
    String? moduleId,
    FractalViewState? view,
    Map<String, Object>? params,
    DateTime? visitedAt,
    String? name,
    bool clearName = false,
  }) {
    return HistoryEntry(
      id: id ?? this.id,
      moduleId: moduleId ?? this.moduleId,
      view: view ?? this.view,
      params: params ?? this.params,
      visitedAt: visitedAt ?? this.visitedAt,
      name: clearName ? null : (name ?? this.name),
    );
  }

  /// Serializes this entry to a JSON-compatible map.
  Map<String, Object?> toJson() {
    return {
      'id': id,
      'moduleId': moduleId,
      'view': {
        'panX': view.pan.x,
        'panY': view.pan.y,
        'zoom': view.zoom,
        'rotX': view.rotation.x,
        'rotY': view.rotation.y,
        'rotZ': view.rotation.z,
      },
      'params': params,
      'visitedAt': visitedAt.toIso8601String(),
      'name': name,
    };
  }

  /// Deserializes a history entry from a JSON map.
  static HistoryEntry fromJson(Map<String, Object?> json) {
    final viewJson = json['view'] as Map<String, Object?>? ?? {};
    return HistoryEntry(
      id: json['id'] as String,
      moduleId: json['moduleId'] as String,
      view: FractalViewState(
        pan: Vector2(
          (viewJson['panX'] as num? ?? 0).toDouble(),
          (viewJson['panY'] as num? ?? 0).toDouble(),
        ),
        zoom: (viewJson['zoom'] as num? ?? 1).toDouble(),
        rotation: Vector3(
          (viewJson['rotX'] as num? ?? 0).toDouble(),
          (viewJson['rotY'] as num? ?? 0).toDouble(),
          (viewJson['rotZ'] as num? ?? 0).toDouble(),
        ),
      ),
      params: decodeHistoryParams(json['params'] as Map?),
      visitedAt: DateTime.tryParse(json['visitedAt'] as String? ?? '') ??
          DateTime.now(),
      name: json['name'] as String?,
    );
  }

  /// Generates a display label for this entry.
  ///
  /// If named, returns the name. Otherwise, returns a
  /// formatted description of the location.
  String get displayLabel {
    if (name != null) return name!;
    final zoomStr = view.zoom >= 10
        ? '${view.zoom.toStringAsFixed(0)}x'
        : '${view.zoom.toStringAsFixed(1)}x';
    return '$moduleId @ $zoomStr';
  }

  /// Checks if this entry represents the same location as another.
  ///
  /// Two entries are at the same location if they have the same
  /// module, view state, and parameters.
  bool isSameLocation(HistoryEntry other) {
    return isSameHistoryLocation(
      moduleId: moduleId,
      view: view,
      params: params,
      otherModuleId: other.moduleId,
      otherView: other.view,
      otherParams: other.params,
    );
  }

  @override
  bool operator ==(Object other) {
    if (identical(this, other)) return true;
    return other is HistoryEntry && other.id == id;
  }

  @override
  int get hashCode => id.hashCode;
}

import 'dart:async' show Timer, unawaited;
import 'package:flutter/foundation.dart';
import 'package:flutter_fractals/core/models/fractal_view_state.dart';
import 'package:flutter_fractals/core/services/history_store.dart';
import 'package:flutter_fractals/features/history/history_entry.dart';
import 'package:flutter_fractals/features/history/history_favorites.dart';
import 'package:flutter_fractals/features/history/history_location.dart';
import 'package:flutter_fractals/features/history/history_replay.dart';
import 'package:flutter_fractals/features/history/history_window.dart';

/// Manages exploration history with back/forward navigation and favorites.
///
/// [HistoryProvider] tracks the user's journey through fractal space,
/// allowing them to:
/// - Navigate back to previously visited locations
/// - Navigate forward after going back
/// - Save favorite spots with custom names
/// - View and jump to any point in history
///
/// History is automatically persisted to local storage.
///
/// {@category State Management}
///
/// Example usage:
/// ```dart
/// final history = HistoryProvider(store: historyStore);
///
/// // Record current location
/// history.recordLocation(
///   moduleId: 'mandelbrot',
///   view: controller.view,
///   params: controller.params,
/// );
///
/// // Navigate back
/// if (history.canGoBack) {
///   final entry = history.goBack();
///   // Apply entry to controller
/// }
/// ```
class HistoryProvider extends ChangeNotifier {
  final HistoryStore _store;

  /// All recorded history entries (oldest first).
  List<HistoryEntry> _history = [];

  /// Current position in history (index into _history).
  /// -1 means no history, 0+ is the index.
  int _currentIndex = -1;

  /// User's saved favorite locations.
  List<HistoryEntry> _favorites = [];

  /// Debounce timer to avoid recording too many entries during quick navigation.
  Timer? _debounceTimer;
  static const Duration _debounceDelay = Duration(milliseconds: 500);

  /// Last recorded state to detect meaningful changes.
  HistoryEntry? _lastRecorded;

  /// Creates a new [HistoryProvider].
  HistoryProvider({required HistoryStore store}) : _store = store {
    _loadFromStorage();
  }

  /// Whether navigation to a previous location is possible.
  bool get canGoBack => _currentIndex > 0;

  /// Whether navigation to a later location is possible.
  ///
  /// Only available after going back.
  bool get canGoForward => _currentIndex < _history.length - 1;

  /// The current history entry, if any.
  HistoryEntry? get currentEntry =>
      _currentIndex >= 0 && _currentIndex < _history.length
          ? _history[_currentIndex]
          : null;

  /// All history entries (oldest first).
  List<HistoryEntry> get history => List.unmodifiable(_history);

  /// Number of entries in history.
  int get historyCount => _history.length;

  /// Current position in history (1-indexed for display).
  int get currentPosition => _currentIndex + 1;

  /// All saved favorites.
  List<HistoryEntry> get favorites => List.unmodifiable(_favorites);

  /// Number of saved favorites.
  int get favoritesCount => _favorites.length;

  void _loadFromStorage() {
    final restored = HistoryRestorePolicy.restore(
      history: _store.loadHistory(),
      favorites: _store.loadFavorites(),
      maxHistoryEntries: HistoryStore.maxHistoryEntries,
      maxFavoriteEntries: HistoryStore.maxFavoriteEntries,
    );
    _history = restored.history;
    _favorites = restored.favorites;
    _currentIndex = restored.currentIndex;
    _lastRecorded = restored.currentEntry;
  }

  /// Records the current location in history.
  ///
  /// If the user has gone back and then makes a change,
  /// forward history is discarded (like a browser).
  ///
  /// Debounces rapid changes to avoid cluttering history
  /// with intermediate positions during smooth navigation.
  void recordLocation({
    required String moduleId,
    required FractalViewState view,
    required Map<String, Object> params,
  }) {
    final viewSnapshot = snapshotHistoryView(view);
    final paramsSnapshot = snapshotHistoryParams(params);

    _debounceTimer?.cancel();
    _debounceTimer = Timer(_debounceDelay, () {
      _doRecordLocation(moduleId, viewSnapshot, paramsSnapshot);
    });
  }

  void _doRecordLocation(
    String moduleId,
    FractalViewState view,
    Map<String, Object> params,
  ) {
    final entry = HistoryEntry.fromState(
      moduleId: moduleId,
      view: view,
      params: params,
    );

    // Skip if essentially the same location as the last entry
    if (_lastRecorded != null && _lastRecorded!.isSameLocation(entry)) {
      return;
    }

    final window = HistoryWindowPolicy.append(
      entries: _history,
      currentIndex: _currentIndex,
      entry: entry,
      maxEntries: HistoryStore.maxHistoryEntries,
    );
    _history = window.entries;
    _currentIndex = window.currentIndex;
    _lastRecorded = entry;

    unawaited(_store.saveHistory(_history));
    notifyListeners();
  }

  /// Navigates back to the previous location in history.
  ///
  /// Returns the entry to navigate to, or null if [canGoBack] is false.
  HistoryEntry? goBack() {
    if (!canGoBack) return null;
    return jumpToIndex(_currentIndex - 1);
  }

  /// Navigates forward to the next location in history.
  ///
  /// Returns the entry to navigate to, or null if [canGoForward] is false.
  HistoryEntry? goForward() {
    if (!canGoForward) return null;
    return jumpToIndex(_currentIndex + 1);
  }

  /// Jumps to a specific entry in history by index.
  HistoryEntry? jumpToIndex(int index) {
    if (index < 0 || index >= _history.length) return null;
    _selectHistoryIndex(index);
    notifyListeners();
    return _history[_currentIndex];
  }

  void _selectHistoryIndex(int index) {
    assert(index >= 0 && index < _history.length);
    // A debounced record captures pre-navigation controller state. If it fires
    // after an explicit history jump, it can silently truncate forward history
    // and move the current entry away from the user's selected replay point.
    cancelPendingRecord();
    _currentIndex = index;
    _lastRecorded = _history[index];
  }

  /// Jumps to a specific entry in history by ID.
  HistoryEntry? jumpToEntry(String entryId) {
    final index = _history.indexWhere((e) => e.id == entryId);
    if (index < 0) return null;
    return jumpToIndex(index);
  }

  /// Saves the current location as a favorite.
  ///
  /// Creates a named copy of the current history entry.
  Future<void> saveCurrentAsFavorite(String name) async {
    if (currentEntry == null) return;

    final favorite = currentEntry!.copyWith(
      id: DateTime.now().microsecondsSinceEpoch.toString(),
      name: name,
      visitedAt: DateTime.now(),
    );

    _favorites = HistoryFavoritesPolicy.append(
      favorites: _favorites,
      favorite: favorite,
      maxFavorites: HistoryStore.maxFavoriteEntries,
    );
    await _store.saveFavorites(_favorites);
    notifyListeners();
  }

  /// Saves a specific entry as a favorite.
  Future<void> saveAsFavorite(HistoryEntry entry, String name) async {
    final favorite = entry.copyWith(
      id: DateTime.now().microsecondsSinceEpoch.toString(),
      name: name,
      visitedAt: DateTime.now(),
    );

    _favorites = HistoryFavoritesPolicy.append(
      favorites: _favorites,
      favorite: favorite,
      maxFavorites: HistoryStore.maxFavoriteEntries,
    );
    await _store.saveFavorites(_favorites);
    notifyListeners();
  }

  /// Removes a favorite by ID.
  Future<void> removeFavorite(String favoriteId) async {
    _favorites.removeWhere((f) => f.id == favoriteId);
    await _store.saveFavorites(_favorites);
    notifyListeners();
  }

  /// Renames a favorite.
  Future<void> renameFavorite(String favoriteId, String newName) async {
    final index = _favorites.indexWhere((f) => f.id == favoriteId);
    if (index < 0) return;

    _favorites[index] = _favorites[index].copyWith(name: newName);
    await _store.saveFavorites(_favorites);
    notifyListeners();
  }

  /// Checks if the current location is saved as a favorite.
  bool isCurrentFavorite() {
    if (currentEntry == null) return false;
    return _favorites.any((f) => f.isSameLocation(currentEntry!));
  }

  void _clearInMemoryHistory() {
    cancelPendingRecord();
    _history.clear();
    _currentIndex = -1;
    _lastRecorded = null;
  }

  /// Clears all history.
  Future<void> clearHistory() async {
    _clearInMemoryHistory();
    await _store.clearHistory();
    notifyListeners();
  }

  /// Clears all favorites.
  Future<void> clearFavorites() async {
    _favorites.clear();
    await _store.clearFavorites();
    notifyListeners();
  }

  /// Applies a history entry to a controller-like object.
  ///
  /// Complete-state controllers should expose `loadState` so replay switches to
  /// the recorded module before applying module-specific params. Legacy test
  /// doubles without `loadState` keep the old structural update sequence.
  void applyToController(HistoryEntry entry, Object controller) {
    applyHistoryEntryToController(entry, controller);
  }

  /// Cancels any pending debounced history record.
  void cancelPendingRecord() {
    _debounceTimer?.cancel();
    _debounceTimer = null;
  }

  @override
  void dispose() {
    cancelPendingRecord();
    super.dispose();
  }
}

import 'package:flutter_fractals/core/models/fractal_view_state.dart';
import 'package:flutter_fractals/features/history/history_entry.dart';
import 'package:flutter_fractals/features/history/history_location.dart';

/// Replayable controller mutation plan for one history entry.
///
/// A history entry is a complete fractal state: module id, parameters, and
/// view. Controllers that expose `loadState(moduleId, params, view)` can apply
/// that complete state in one step so module-specific params are normalized
/// against the recorded module. Older controller-like test doubles without
/// `loadState` keep the legacy incremental replay sequence.
final class HistoryControllerReplayPlan {
  HistoryControllerReplayPlan({
    required this.moduleId,
    required FractalViewState view,
    required Map<String, Object> params,
  })  : view = snapshotHistoryView(view),
        params = snapshotHistoryParams(params);

  factory HistoryControllerReplayPlan.fromEntry(HistoryEntry entry) {
    return HistoryControllerReplayPlan(
      moduleId: entry.moduleId,
      view: entry.view,
      params: entry.params,
    );
  }

  final String moduleId;
  final FractalViewState view;
  final Map<String, Object> params;

  void applyTo(Object controller) {
    if (_tryApplyCompleteState(controller)) return;
    _applyIncrementalState(controller);
  }

  bool _tryApplyCompleteState(Object controller) {
    final Function loadState;
    try {
      loadState = (controller as dynamic).loadState as Function;
    } on NoSuchMethodError {
      return false;
    }

    Function.apply(loadState, const [], {
      #moduleId: moduleId,
      #params: params,
      #view: view,
    });
    return true;
  }

  void _applyIncrementalState(Object controller) {
    final target = controller as dynamic;

    for (final paramEntry in params.entries) {
      try {
        target.updateParam(paramEntry.key, paramEntry.value);
      } catch (_) {
        // Parameter may not exist in current module.
      }
    }

    target.updateZoom(view.zoom);
    target.updatePan(view.pan);
    target.updateRotation(view.rotation);
  }
}

/// Applies a complete history entry to a controller-like object.
void applyHistoryEntryToController(HistoryEntry entry, Object controller) {
  HistoryControllerReplayPlan.fromEntry(entry).applyTo(controller);
}

import 'dart:convert';

import 'package:flutter_test/flutter_test.dart';
import 'package:flutter_fractals/core/models/fractal_view_state.dart';
import 'package:flutter_fractals/features/history/history_entry.dart';
import 'package:vector_math/vector_math.dart';

HistoryEntry _entry({
  String moduleId = 'mandelbrot',
  double zoom = 1,
  Map<String, Object> params = const <String, Object>{},
}) {
  return HistoryEntry(
    id: 'entry-$moduleId-$zoom-${params.length}',
    moduleId: moduleId,
    view: FractalViewState(
      pan: Vector2.zero(),
      zoom: zoom,
      rotation: Vector3.zero(),
    ),
    params: params,
    visitedAt: DateTime.utc(2024),
  );
}

void main() {
  group('HistoryEntry location identity', () {
    test('treats matching module, view, and params as the same location', () {
      final first = _entry(params: {'iterations': 100, 'bailout': 4.0});
      final second = _entry(params: {'bailout': 4.0, 'iterations': 100});

      expect(first.isSameLocation(second), isTrue);
    });

    test('treats parameter changes as a different location', () {
      final first = _entry(params: {'iterations': 100});
      final second = _entry(params: {'iterations': 250});

      expect(first.isSameLocation(second), isFalse);
    });

    test('treats JSON-like list parameter values as replayable values', () {
      final first = _entry(params: {
        'paletteStops': [0.0, 0.5, 1.0],
      });
      final second = _entry(params: {
        'paletteStops': [0.0, 0.5, 1.0],
      });

      expect(first.isSameLocation(second), isTrue);
    });

    test('treats view changes as a different location', () {
      final first = _entry(zoom: 1);
      final second = _entry(zoom: 2);

      expect(first.isSameLocation(second), isFalse);
    });

    test('snapshots mutable view vectors and params when created from state',
        () {
      final pan = Vector2(1, 2);
      final rotation = Vector3(3, 4, 5);
      final params = <String, Object>{'iterations': 100};
      final entry = HistoryEntry.fromState(
        moduleId: 'mandelbrot',
        view: FractalViewState(pan: pan, zoom: 6, rotation: rotation),
        params: params,
      );

      pan.setValues(7, 8);
      rotation.setValues(9, 10, 11);
      params['iterations'] = 250;

      expect(entry.view.pan.x, 1);
      expect(entry.view.pan.y, 2);
      expect(entry.view.rotation.x, 3);
      expect(entry.view.rotation.y, 4);
      expect(entry.view.rotation.z, 5);
      expect(entry.params, {'iterations': 100});
    });

    test('constructor snapshots mutable view and freezes nested params', () {
      final pan = Vector2(1, 2);
      final rotation = Vector3(3, 4, 5);
      final paletteStops = <Object?>[
        0.0,
        <String, Object?>{
          'position': 0.5,
          'rgb': <Object?>[32, 64, 128],
        },
      ];
      final params = <String, Object>{'paletteStops': paletteStops};

      final entry = HistoryEntry(
        id: 'entry',
        moduleId: 'mandelbrot',
        view: FractalViewState(pan: pan, zoom: 6, rotation: rotation),
        params: params,
        visitedAt: DateTime.utc(2024),
      );

      pan.setValues(7, 8);
      rotation.setValues(9, 10, 11);
      (paletteStops[1] as Map<String, Object?>)['position'] = 0.75;
      ((paletteStops[1] as Map<String, Object?>)['rgb'] as List<Object?>)[0] =
          255;
      paletteStops.add(1.0);

      expect(entry.view.pan.x, 1);
      expect(entry.view.pan.y, 2);
      expect(entry.view.rotation.x, 3);
      expect(entry.view.rotation.y, 4);
      expect(entry.view.rotation.z, 5);
      expect(entry.params, {
        'paletteStops': [
          0.0,
          {
            'position': 0.5,
            'rgb': [32, 64, 128],
          },
        ],
      });
      expect(
        () => entry.params['paletteStops'] = <Object?>[],
        throwsUnsupportedError,
      );
      expect(
        () => (entry.params['paletteStops'] as List<Object?>).add(1.0),
        throwsUnsupportedError,
      );
      expect(
        () => ((entry.params['paletteStops'] as List<Object?>)[1]
            as Map<String, Object?>)['position'] = 0.75,
        throwsUnsupportedError,
      );
    });

    test('serializes nested map parameter keys as JSON object keys', () {
      final entry = HistoryEntry.fromState(
        moduleId: 'mandelbrot',
        view: FractalViewState(
          pan: Vector2.zero(),
          zoom: 6,
          rotation: Vector3.zero(),
        ),
        params: <String, Object>{
          'metadata': <Object, Object>{1: 'one'},
        },
      );

      final encoded = jsonEncode(entry.toJson());
      final decoded = jsonDecode(encoded) as Map<String, Object?>;
      final restored = HistoryEntry.fromJson(decoded);

      expect(restored.params, {
        'metadata': {'1': 'one'},
      });
    });

    test('drops stale top-level null params while preserving replayable entry',
        () {
      final restored = HistoryEntry.fromJson({
        'id': 'entry-with-stale-param',
        'moduleId': 'mandelbrot',
        'view': <String, Object?>{
          'panX': 0,
          'panY': 0,
          'zoom': 1,
          'rotX': 0,
          'rotY': 0,
          'rotZ': 0,
        },
        'params': <String, Object?>{
          'iterations': 120,
          'staleNull': null,
          'paletteStops': <Object?>[
            0.0,
            null,
            <String, Object?>{'position': null},
          ],
        },
        'visitedAt': '2024-01-01T00:00:00.000Z',
        'name': null,
      });

      expect(restored.id, 'entry-with-stale-param');
      expect(restored.params, {
        'iterations': 120,
        'paletteStops': [
          0.0,
          null,
          {'position': null},
        ],
      });
    });

    test('deep-snapshots nested JSON-like params when created from state', () {
      final paletteStops = <Object?>[
        0.0,
        <String, Object?>{
          'position': 0.5,
          'rgb': <Object?>[32, 64, 128],
        },
        1.0,
      ];
      final params = <String, Object>{'paletteStops': paletteStops};

      final entry = HistoryEntry.fromState(
        moduleId: 'mandelbrot',
        view: FractalViewState(
          pan: Vector2.zero(),
          zoom: 6,
          rotation: Vector3.zero(),
        ),
        params: params,
      );

      (paletteStops[1] as Map<String, Object?>)['position'] = 0.75;
      ((paletteStops[1] as Map<String, Object?>)['rgb'] as List<Object?>)[0] =
          255;
      paletteStops.add(2.0);

      expect(entry.params, {
        'paletteStops': [
          0.0,
          {
            'position': 0.5,
            'rgb': [32, 64, 128],
          },
          1.0,
        ],
      });
    });

    test('snapshots replacement view and params when copied', () {
      final replacementPan = Vector2(1, 2);
      final replacementRotation = Vector3(3, 4, 5);
      final replacementStops = <Object?>[
        0.0,
        <String, Object?>{
          'position': 0.5,
          'rgb': <Object?>[32, 64, 128],
        },
      ];
      final replacementParams = <String, Object>{
        'paletteStops': replacementStops,
      };

      final copied = _entry().copyWith(
        view: FractalViewState(
          pan: replacementPan,
          zoom: 6,
          rotation: replacementRotation,
        ),
        params: replacementParams,
      );

      replacementPan.setValues(7, 8);
      replacementRotation.setValues(9, 10, 11);
      (replacementStops[1] as Map<String, Object?>)['position'] = 0.75;
      ((replacementStops[1] as Map<String, Object?>)['rgb']
          as List<Object?>)[0] = 255;
      replacementStops.add(1.0);

      expect(copied.view.pan.x, 1);
      expect(copied.view.pan.y, 2);
      expect(copied.view.rotation.x, 3);
      expect(copied.view.rotation.y, 4);
      expect(copied.view.rotation.z, 5);
      expect(copied.params, {
        'paletteStops': [
          0.0,
          {
            'position': 0.5,
            'rgb': [32, 64, 128],
          },
        ],
      });
    });
  });
}

import 'dart:convert';

import 'package:flutter_fractals/core/models/fractal_view_state.dart';
import 'package:flutter_fractals/core/modules/module_registry.dart';
import 'package:flutter_fractals/core/services/history_store.dart';
import 'package:flutter_fractals/features/history/history_entry.dart';
import 'package:flutter_fractals/features/history/history_provider.dart';
import 'package:flutter_fractals/features/renderer/providers/fractal_provider.dart';
import 'package:flutter_test/flutter_test.dart';
import 'package:shared_preferences/shared_preferences.dart';
import 'package:vector_math/vector_math.dart';

FractalViewState _view(double zoom) {
  return FractalViewState(
    pan: Vector2.zero(),
    zoom: zoom,
    rotation: Vector3.zero(),
  );
}

Map<String, Object?> _entryJson(double zoom) {
  return HistoryEntry.fromState(
    moduleId: 'mandelbrot',
    view: _view(zoom),
    params: const <String, Object>{'iterations': 100},
  ).toJson();
}

Future<void> _recordAndFlush(
  WidgetTester tester,
  HistoryProvider provider, {
  required double zoom,
}) async {
  provider.recordLocation(
    moduleId: 'mandelbrot',
    view: _view(zoom),
    params: const <String, Object>{'iterations': 100},
  );
  await tester.pump(const Duration(milliseconds: 501));
}

final class _LegacyReplayController {
  final params = <String, Object>{};
  double? zoom;
  Vector2? pan;
  Vector3? rotation;

  void updateParam(String id, Object value) {
    params[id] = value;
  }

  void updateZoom(double value) {
    zoom = value;
  }

  void updatePan(Vector2 value) {
    pan = Vector2.copy(value);
  }

  void updateRotation(Vector3 value) {
    rotation = Vector3.copy(value);
  }
}

void main() {
  group('HistoryProvider navigation recording', () {
    setUp(() {
      TestWidgetsFlutterBinding.ensureInitialized();
      SharedPreferences.setMockInitialValues({});
    });

    testWidgets(
        'replaying the current back entry does not truncate forward history',
        (tester) async {
      final store = await HistoryStore.create();
      final provider = HistoryProvider(store: store);
      addTearDown(provider.dispose);

      await _recordAndFlush(tester, provider, zoom: 1);
      await _recordAndFlush(tester, provider, zoom: 2);
      await _recordAndFlush(tester, provider, zoom: 3);

      final restored = provider.goBack();
      expect(restored, isNotNull);
      expect(provider.currentPosition, 2);
      expect(provider.canGoForward, isTrue);

      await _recordAndFlush(tester, provider, zoom: 2);

      expect(provider.historyCount, 3);
      expect(provider.currentPosition, 2);
      expect(provider.canGoForward, isTrue);
      expect(provider.currentEntry, same(restored));
    });

    testWidgets('history navigation cancels pending pre-navigation records',
        (tester) async {
      final store = await HistoryStore.create();
      final provider = HistoryProvider(store: store);
      addTearDown(provider.dispose);

      await _recordAndFlush(tester, provider, zoom: 1);
      await _recordAndFlush(tester, provider, zoom: 2);

      provider.recordLocation(
        moduleId: 'mandelbrot',
        view: _view(3),
        params: const <String, Object>{'iterations': 100},
      );

      final restored = provider.goBack();
      expect(restored, isNotNull);
      expect(restored!.view.zoom, 1);
      expect(provider.currentPosition, 1);
      expect(provider.canGoForward, isTrue);

      await tester.pump(const Duration(milliseconds: 501));

      expect(provider.historyCount, 2);
      expect(provider.currentPosition, 1);
      expect(provider.currentEntry, same(restored));
      expect(provider.canGoForward, isTrue);
      expect(provider.history.map((entry) => entry.view.zoom), [1, 2]);
    });

    testWidgets('records the state passed to the debounced record call',
        (tester) async {
      final store = await HistoryStore.create();
      final provider = HistoryProvider(store: store);
      addTearDown(provider.dispose);

      final pan = Vector2(1, 2);
      final rotation = Vector3(3, 4, 5);
      final params = <String, Object>{'iterations': 100};
      provider.recordLocation(
        moduleId: 'mandelbrot',
        view: FractalViewState(pan: pan, zoom: 6, rotation: rotation),
        params: params,
      );

      pan.setValues(7, 8);
      rotation.setValues(9, 10, 11);
      params['iterations'] = 250;
      await tester.pump(const Duration(milliseconds: 501));

      final entry = provider.currentEntry;
      expect(entry, isNotNull);
      expect(entry!.view.pan.x, 1);
      expect(entry.view.pan.y, 2);
      expect(entry.view.rotation.x, 3);
      expect(entry.view.rotation.y, 4);
      expect(entry.view.rotation.z, 5);
      expect(entry.params, {'iterations': 100});
    });

    testWidgets('keeps in-memory history capped to the persisted max depth',
        (tester) async {
      final store = await HistoryStore.create();
      final provider = HistoryProvider(store: store);
      addTearDown(provider.dispose);

      for (var i = 0; i < HistoryStore.maxHistoryEntries + 2; i++) {
        await _recordAndFlush(tester, provider, zoom: i + 1.0);
      }

      expect(provider.historyCount, HistoryStore.maxHistoryEntries);
      expect(provider.currentPosition, HistoryStore.maxHistoryEntries);
      expect(provider.history.first.view.zoom, 3.0);
      expect(provider.currentEntry!.view.zoom, 102.0);
    });

    testWidgets('keeps in-memory favorites capped to persisted max depth',
        (tester) async {
      final store = await HistoryStore.create();
      final provider = HistoryProvider(store: store);
      addTearDown(provider.dispose);

      await _recordAndFlush(tester, provider, zoom: 1);

      for (var i = 0; i < HistoryStore.maxFavoriteEntries + 2; i++) {
        await provider.saveCurrentAsFavorite('favorite $i');
      }

      expect(provider.favoritesCount, HistoryStore.maxFavoriteEntries);
      expect(provider.favorites.first.name, 'favorite 2');
      expect(provider.favorites.last.name, 'favorite 501');
      expect(store.loadFavorites().length, HistoryStore.maxFavoriteEntries);
    });

    testWidgets('restored history and favorites are capped before display',
        (tester) async {
      SharedPreferences.setMockInitialValues({
        'exploration_history': jsonEncode([
          for (var i = 0; i < HistoryStore.maxHistoryEntries + 2; i++)
            _entryJson(i + 1.0),
        ]),
        'exploration_favorites': jsonEncode([
          for (var i = 0; i < HistoryStore.maxFavoriteEntries + 2; i++)
            _entryJson(i + 1.0),
        ]),
      });

      final store = await HistoryStore.create();
      final provider = HistoryProvider(store: store);
      addTearDown(provider.dispose);

      expect(provider.historyCount, HistoryStore.maxHistoryEntries);
      expect(provider.currentPosition, HistoryStore.maxHistoryEntries);
      expect(provider.history.first.view.zoom, 3.0);
      expect(provider.currentEntry!.view.zoom, 102.0);
      expect(provider.favoritesCount, HistoryStore.maxFavoriteEntries);
      expect(provider.favorites.first.view.zoom, 3.0);
      expect(provider.favorites.last.view.zoom, 502.0);
    });

    testWidgets('clearHistory cancels pending debounced records',
        (tester) async {
      final store = await HistoryStore.create();
      final provider = HistoryProvider(store: store);
      addTearDown(provider.dispose);

      provider.recordLocation(
        moduleId: 'mandelbrot',
        view: _view(6),
        params: const <String, Object>{'iterations': 100},
      );
      await provider.clearHistory();
      await tester.pump(const Duration(milliseconds: 501));

      expect(provider.historyCount, 0);
      expect(provider.currentEntry, isNull);
      expect(store.loadHistory(), isEmpty);
    });

    testWidgets('history replay switches to the recorded module before state',
        (tester) async {
      final store = await HistoryStore.create();
      final provider = HistoryProvider(store: store);
      addTearDown(provider.dispose);

      final registry = ModuleRegistry();
      final controller = FractalController(registry);
      addTearDown(controller.dispose);

      final entry = HistoryEntry(
        id: 'julia-replay',
        moduleId: 'julia',
        view: FractalViewState(
          pan: Vector2(0.25, -0.5),
          zoom: 2.5,
          rotation: Vector3(0.1, 0.2, 0.3),
        ),
        params: const <String, Object>{
          'iterations': 222,
          'bailout': 4.5,
          'colorScheme': 2,
        },
        visitedAt: DateTime.utc(2024),
      );

      provider.applyToController(entry, controller);

      expect(controller.module.id, 'julia');
      expect(controller.params['iterations'], 222);
      expect(controller.params['bailout'], closeTo(4.5, 1e-12));
      expect(controller.params['colorScheme'], 2);
      expect(controller.view.pan, Vector2(0.25, -0.5));
      expect(controller.view.zoom, 2.5);
      expect(controller.view.rotation, Vector3(0.1, 0.2, 0.3));
    });

    testWidgets('history replay keeps legacy structural controllers working',
        (tester) async {
      final store = await HistoryStore.create();
      final provider = HistoryProvider(store: store);
      addTearDown(provider.dispose);

      final controller = _LegacyReplayController();
      final entry = HistoryEntry(
        id: 'legacy-replay',
        moduleId: 'mandelbrot',
        view: FractalViewState(
          pan: Vector2(-0.25, 0.5),
          zoom: 3.5,
          rotation: Vector3(0.4, 0.5, 0.6),
        ),
        params: const <String, Object>{'iterations': 180},
        visitedAt: DateTime.utc(2024),
      );

      provider.applyToController(entry, controller);

      expect(controller.params, {'iterations': 180});
      expect(controller.zoom, 3.5);
      expect(controller.pan, Vector2(-0.25, 0.5));
      expect(controller.rotation, Vector3(0.4, 0.5, 0.6));
    });
  });
}

import 'package:vector_math/vector_math.dart';
import 'package:flutter_fractals/core/models/fractal_view_state.dart';

/// Creates an immutable-by-convention history snapshot of a mutable view state.
///
/// [FractalViewState] stores mutable vector_math objects, so history must clone
/// those vectors at the record boundary to keep debounced writes replayable.
FractalViewState snapshotHistoryView(FractalViewState view) {
  return FractalViewState(
    pan: Vector2.copy(view.pan),
    zoom: view.zoom,
    rotation: Vector3.copy(view.rotation),
  );
}

/// Creates a deep JSON-like snapshot of parameters at the record boundary.
Map<String, Object> snapshotHistoryParams(Map<String, Object> params) {
  return Map<String, Object>.unmodifiable({
    for (final entry in params.entries)
      entry.key: snapshotHistoryParamValue(entry.value),
  });
}

/// Decodes persisted history params without letting one stale null field drop
/// an otherwise replayable entry.
Map<String, Object> decodeHistoryParams(Map? params) {
  if (params == null) return const <String, Object>{};

  final decoded = <String, Object>{};
  for (final entry in params.entries) {
    final key = entry.key;
    final value = entry.value;
    if (key == null || value == null) continue;
    decoded[key.toString()] = snapshotHistoryParamValue(value as Object);
  }
  return Map<String, Object>.unmodifiable(decoded);
}

/// Deep-copies JSON-like parameter values so history replay is not affected by
/// later mutations of nested list/map values owned by controllers or widgets.
///
/// Nested map keys are normalized to strings because history entries are
/// persisted as JSON objects. Without this, a controller-owned metadata map
/// with enum/int keys can make the whole history save fail during jsonEncode.
/// Returned collections are unmodifiable so public [HistoryEntry] reads cannot
/// mutate stored history without going through provider methods.
Object snapshotHistoryParamValue(Object value) {
  if (value is List) {
    return List<Object?>.unmodifiable([
      for (final item in value)
        item is Object ? snapshotHistoryParamValue(item) : item,
    ]);
  }

  if (value is Map) {
    return Map<String, Object?>.unmodifiable({
      for (final entry in value.entries)
        entry.key.toString(): entry.value is Object
            ? snapshotHistoryParamValue(entry.value as Object)
            : entry.value,
    });
  }

  return value;
}

/// Pure location-equivalence contract for history de-duplication.
///
/// A history location is the restorable fractal state: module, view, and
/// parameters. Metadata such as entry id, favorite name, and timestamp is not
/// part of location identity.
bool isSameHistoryLocation({
  required String moduleId,
  required FractalViewState view,
  required Map<String, Object> params,
  required String otherModuleId,
  required FractalViewState otherView,
  required Map<String, Object> otherParams,
}) {
  if (moduleId != otherModuleId) {
    return false;
  }
  if (view.zoom != otherView.zoom) {
    return false;
  }
  if (view.pan.x != otherView.pan.x || view.pan.y != otherView.pan.y) {
    return false;
  }
  if (view.rotation.x != otherView.rotation.x ||
      view.rotation.y != otherView.rotation.y ||
      view.rotation.z != otherView.rotation.z) {
    return false;
  }
  return haveSameHistoryParams(params, otherParams);
}

/// Compares history parameter snapshots without relying on map iteration order.
bool haveSameHistoryParams(
  Map<String, Object> params,
  Map<String, Object> otherParams,
) {
  if (params.length != otherParams.length) {
    return false;
  }

  for (final entry in params.entries) {
    if (!otherParams.containsKey(entry.key)) {
      return false;
    }
    if (!areSameHistoryParamValue(entry.value, otherParams[entry.key])) {
      return false;
    }
  }

  return true;
}

/// Compares JSON-like history parameter values by value rather than identity.
///
/// Persisted params can contain nested lists/maps after JSON decode. Dart's
/// collection equality is identity-based, which would make two replayed
/// locations look different even when their serialized parameter values match.
bool areSameHistoryParamValue(Object? value, Object? otherValue) {
  if (identical(value, otherValue)) return true;

  if (value is List && otherValue is List) {
    if (value.length != otherValue.length) return false;
    for (var i = 0; i < value.length; i++) {
      if (!areSameHistoryParamValue(
          value[i] as Object?, otherValue[i] as Object?)) {
        return false;
      }
    }
    return true;
  }

  if (value is Map && otherValue is Map) {
    if (value.length != otherValue.length) return false;
    for (final entry in value.entries) {
      if (!otherValue.containsKey(entry.key)) return false;
      if (!areSameHistoryParamValue(
        entry.value as Object?,
        otherValue[entry.key] as Object?,
      )) {
        return false;
      }
    }
    return true;
  }

  return value == otherValue;
}

import 'package:flutter_fractals/features/history/history_entry.dart';

/// Result of applying a history-list mutation.
class HistoryWindow {
  /// History entries in display order (oldest first).
  final List<HistoryEntry> entries;

  /// Current selected index into [entries], or -1 when empty.
  final int currentIndex;

  const HistoryWindow({
    required this.entries,
    required this.currentIndex,
  });
}

/// Restored history and favorite lists after applying in-memory caps.
class HistoryRestoreSnapshot {
  final List<HistoryEntry> history;
  final int currentIndex;
  final List<HistoryEntry> favorites;

  const HistoryRestoreSnapshot({
    required this.history,
    required this.currentIndex,
    required this.favorites,
  });

  HistoryEntry? get currentEntry =>
      currentIndex >= 0 && currentIndex < history.length
          ? history[currentIndex]
          : null;
}

/// Pure storage-restore policy shared by provider boot and tests.
///
/// Storage writes are capped, but older/corrupted preferences can still contain
/// too many entries. Normalize immediately so first-frame UI state matches the
/// same bounded contract as persisted writes.
class HistoryRestorePolicy {
  const HistoryRestorePolicy._();

  static HistoryRestoreSnapshot restore({
    required List<HistoryEntry> history,
    required List<HistoryEntry> favorites,
    required int maxHistoryEntries,
    required int maxFavoriteEntries,
  }) {
    assert(maxHistoryEntries > 0);
    assert(maxFavoriteEntries > 0);

    final restoredHistory = _mostRecent(history, maxHistoryEntries);
    return HistoryRestoreSnapshot(
      history: restoredHistory,
      currentIndex: restoredHistory.isEmpty ? -1 : restoredHistory.length - 1,
      favorites: _mostRecent(favorites, maxFavoriteEntries),
    );
  }

  static List<HistoryEntry> _mostRecent(
    List<HistoryEntry> entries,
    int maxEntries,
  ) {
    if (entries.length <= maxEntries) return List<HistoryEntry>.of(entries);
    return entries.sublist(entries.length - maxEntries);
  }
}

/// Pure history append policy shared by recording and tests.
///
/// The in-memory provider must enforce the same maximum depth as persistence;
/// otherwise entries silently disappear only after app restart.
class HistoryWindowPolicy {
  const HistoryWindowPolicy._();

  static HistoryWindow append({
    required List<HistoryEntry> entries,
    required int currentIndex,
    required HistoryEntry entry,
    required int maxEntries,
  }) {
    assert(maxEntries > 0);

    final nextEntries = currentIndex >= 0 && currentIndex < entries.length - 1
        ? entries.sublist(0, currentIndex + 1)
        : List<HistoryEntry>.of(entries);

    nextEntries.add(entry);

    if (nextEntries.length > maxEntries) {
      nextEntries.removeRange(0, nextEntries.length - maxEntries);
    }

    return HistoryWindow(
      entries: nextEntries,
      currentIndex: nextEntries.length - 1,
    );
  }
}

import 'package:flutter_fractals/features/history/history_entry.dart';

/// Pure favorite-list append policy shared by provider mutations.
///
/// Persistence caps favorites to keep local storage bounded. The provider must
/// apply the same cap before notifying listeners so in-memory UI state and the
/// next app launch agree about which favorites still exist.
class HistoryFavoritesPolicy {
  const HistoryFavoritesPolicy._();

  static List<HistoryEntry> append({
    required List<HistoryEntry> favorites,
    required HistoryEntry favorite,
    required int maxFavorites,
  }) {
    assert(maxFavorites > 0);

    final nextFavorites = List<HistoryEntry>.of(favorites)..add(favorite);
    if (nextFavorites.length > maxFavorites) {
      nextFavorites.removeRange(0, nextFavorites.length - maxFavorites);
    }
    return nextFavorites;
  }
}

import 'package:flutter_test/flutter_test.dart';
import 'package:shared_preferences/shared_preferences.dart';
import 'package:vector_math/vector_math.dart';
import 'package:flutter_fractals/core/services/history_store.dart';
import 'package:flutter_fractals/features/history/history_entry.dart';
import 'package:flutter_fractals/core/models/fractal_view_state.dart';

HistoryEntry _makeEntry(String id, {String moduleId = 'mandelbrot'}) {
  return HistoryEntry(
    id: id,
    moduleId: moduleId,
    view: FractalViewState(
      pan: Vector2(0.0, 0.0),
      zoom: 1.0,
      rotation: Vector3.zero(),
    ),
    params: {},
    visitedAt: DateTime.utc(2024, 1, 1),
  );
}

void main() {
  group('HistoryStore', () {
    setUp(() {
      TestWidgetsFlutterBinding.ensureInitialized();
      SharedPreferences.setMockInitialValues({});
    });

    test('create() factory returns a valid store', () async {
      final store = await HistoryStore.create();
      expect(store, isNotNull);
    });

    test('loadHistory returns empty list when no data stored', () async {
      final store = await HistoryStore.create();
      expect(store.loadHistory(), isEmpty);
    });

    test('saveHistory and loadHistory round-trip entries', () async {
      final store = await HistoryStore.create();
      final entries = [
        _makeEntry('1', moduleId: 'mandelbrot'),
        _makeEntry('2', moduleId: 'julia'),
      ];

      await store.saveHistory(entries);
      final loaded = store.loadHistory();

      expect(loaded, hasLength(2));
      expect(loaded[0].id, equals('1'));
      expect(loaded[0].moduleId, equals('mandelbrot'));
      expect(loaded[1].id, equals('2'));
      expect(loaded[1].moduleId, equals('julia'));
    });

    test('history entries maintain insertion order', () async {
      final store = await HistoryStore.create();
      final entries = [
        _makeEntry('first', moduleId: 'mandelbrot'),
        _makeEntry('second', moduleId: 'julia'),
        _makeEntry('third', moduleId: 'burning_ship'),
      ];

      await store.saveHistory(entries);
      final loaded = store.loadHistory();

      expect(loaded, hasLength(3));
      expect(loaded[0].id, equals('first'));
      expect(loaded[1].id, equals('second'));
      expect(loaded[2].id, equals('third'));
    });

    test('saveHistory caps oldest-first history to most recent entries',
        () async {
      final store = await HistoryStore.create();
      final entries = [
        for (var i = 0; i < HistoryStore.maxHistoryEntries + 2; i++)
          _makeEntry('history_$i'),
      ];

      await store.saveHistory(entries);
      final loaded = store.loadHistory();

      expect(loaded, hasLength(HistoryStore.maxHistoryEntries));
      expect(loaded.first.id, 'history_2');
      expect(loaded.last.id, 'history_${HistoryStore.maxHistoryEntries + 1}');
    });

    test('loadFavorites returns empty list when no data stored', () async {
      final store = await HistoryStore.create();
      expect(store.loadFavorites(), isEmpty);
    });

    test('addFavorite appends entry to favorites', () async {
      final store = await HistoryStore.create();
      final entry = _makeEntry('fav1');

      await store.addFavorite(entry);
      final favorites = store.loadFavorites();

      expect(favorites, hasLength(1));
      expect(favorites.first.id, equals('fav1'));
    });

    test('addFavorite does not duplicate existing entry', () async {
      final store = await HistoryStore.create();
      final entry = _makeEntry('fav1');

      await store.addFavorite(entry);
      await store.addFavorite(entry);
      final favorites = store.loadFavorites();

      expect(favorites, hasLength(1));
    });

    test('saveFavorites caps oldest-first favorites to most recent entries',
        () async {
      final store = await HistoryStore.create();
      final entries = [
        for (var i = 0; i < HistoryStore.maxFavoriteEntries + 2; i++)
          _makeEntry('favorite_$i'),
      ];

      await store.saveFavorites(entries);
      final loaded = store.loadFavorites();

      expect(loaded, hasLength(HistoryStore.maxFavoriteEntries));
      expect(loaded.first.id, 'favorite_2');
      expect(loaded.last.id, 'favorite_${HistoryStore.maxFavoriteEntries + 1}');
    });

    test('removeFavorite removes entry by ID', () async {
      final store = await HistoryStore.create();
      await store.addFavorite(_makeEntry('fav1'));
      await store.addFavorite(_makeEntry('fav2'));

      await store.removeFavorite('fav1');
      final favorites = store.loadFavorites();

      expect(favorites, hasLength(1));
      expect(favorites.first.id, equals('fav2'));
    });

    test('clearHistory removes all history', () async {
      final store = await HistoryStore.create();
      await store.saveHistory([_makeEntry('1'), _makeEntry('2')]);

      await store.clearHistory();
      expect(store.loadHistory(), isEmpty);
    });

    test('loadHistory handles corrupted JSON gracefully', () async {
      SharedPreferences.setMockInitialValues({
        'exploration_history': 'not valid json {{{',
      });
      final store = await HistoryStore.create();
      expect(store.loadHistory(), isEmpty);
    });

    test('loadHistory skips corrupted individual entries', () async {
      // Valid JSON array but one entry has missing required fields.
      SharedPreferences.setMockInitialValues({
        'exploration_history':
            '[{"id":"1","moduleId":"mandelbrot","view":{"panX":0,"panY":0,"zoom":1,"rotX":0,"rotY":0,"rotZ":0},"params":{},"visitedAt":"2024-01-01T00:00:00.000Z"},{"bad":"entry"}]',
      });
      final store = await HistoryStore.create();
      final loaded = store.loadHistory();
      // The valid entry should be present; the corrupted one silently skipped.
      expect(loaded, hasLength(1));
      expect(loaded.first.id, equals('1'));
    });
  });
}

import 'dart:async';

import 'package:flutter/foundation.dart';
import 'package:flutter/services.dart';
import 'package:flutter_fractals/core/models/fractal_view_state.dart';
import 'package:vector_math/vector_math.dart';

/// Parsed deep link data containing fractal configuration.
///
/// This class represents the configuration extracted from a deep link URL
/// like `fractalforge://view?type=mandelbrot&zoom=10&x=0.5`.
///
/// {@category Services}
class DeepLinkData {
  /// The fractal module ID (e.g., 'mandelbrot', 'julia', 'mandelbulb').
  final String type;

  /// Zoom level (magnification).
  final double? zoom;

  /// Pan X coordinate (2D fractals).
  final double? x;

  /// Pan Y coordinate (2D fractals).
  final double? y;

  /// Rotation X angle in radians (3D fractals).
  final double? rotX;

  /// Rotation Y angle in radians (3D fractals).
  final double? rotY;

  /// Rotation Z angle in radians (3D fractals).
  final double? rotZ;

  /// Number of iterations.
  final int? iterations;

  /// Bailout radius.
  final double? bailout;

  /// Color scheme index.
  final int? colorScheme;

  /// Power parameter (for fractals like Mandelbulb).
  final double? power;

  /// Julia set real constant (c.x) from the public `juliaX` URL alias.
  final double? juliaX;

  /// Julia set imaginary constant (c.y) from the public `juliaY` URL alias.
  final double? juliaY;

  const DeepLinkData({
    required this.type,
    this.zoom,
    this.x,
    this.y,
    this.rotX,
    this.rotY,
    this.rotZ,
    this.iterations,
    this.bailout,
    this.colorScheme,
    this.power,
    this.juliaX,
    this.juliaY,
  });

  /// Creates a [FractalViewState] from the parsed deep link data.
  FractalViewState toViewState() {
    return FractalViewState(
      pan: Vector2(x ?? 0.0, y ?? 0.0),
      zoom: zoom ?? 1.0,
      rotation: Vector3(rotX ?? 0.0, rotY ?? 0.0, rotZ ?? 0.0),
    );
  }

  /// Extracts fractal parameters from the deep link data.
  ///
  /// Returns a map of parameter IDs to values.
  Map<String, Object> toParams() {
    final params = <String, Object>{};

    if (iterations != null) params['iterations'] = iterations!;
    if (bailout != null) params['bailout'] = bailout!;
    if (colorScheme != null) params['colorScheme'] = colorScheme!;
    if (power != null) params['power'] = power!;
    _DeepLinkJuliaConstantParams.addRuntimeParams(
      params,
      real: juliaX,
      imaginary: juliaY,
    );

    return params;
  }

  @override
  String toString() {
    return 'DeepLinkData(type: $type, zoom: $zoom, x: $x, y: $y, '
        'rotX: $rotX, rotY: $rotY, rotZ: $rotZ, iterations: $iterations, '
        'bailout: $bailout, colorScheme: $colorScheme, power: $power, '
        'juliaX: $juliaX, juliaY: $juliaY)';
  }
}

/// Service for handling deep links with the `fractalforge://` scheme.
///
/// Supports URLs like:
/// - `fractalforge://view?type=mandelbrot&zoom=10&x=-0.5&y=0.1`
/// - `fractalforge://view?type=julia&juliaX=-0.7&juliaY=0.27&colorScheme=2`
/// - `fractalforge://view?type=mandelbulb&rotX=0.5&rotY=0.3&power=8`
///
/// {@category Services}
enum _DeepLinkRouteKind {
  customSchemeView,
  universalLinkView,
  rejected,
}

/// Shared view-route path contract for custom-scheme and universal links.
class _DeepLinkViewRoutePath {
  static const String pathOnlyView = DeepLinkService.host;
  static const String absoluteView = '/${DeepLinkService.host}';

  const _DeepLinkViewRoutePath._();

  /// A URI path that addresses the view route itself, with or without the
  /// canonical trailing slash some universal-link providers append.
  static bool isAbsoluteViewPath(String path) {
    return path == absoluteView || path == '$absoluteView/';
  }

  static bool isAuthorityRoot(String path) {
    return path.isEmpty || path == '/';
  }

  static bool isPathOnlyCustomSchemeView(String path) {
    return path == pathOnlyView || isAbsoluteViewPath(path);
  }
}

/// Normalized custom-scheme route shape.
///
/// `fractalforge://view?...` uses `view` as URI authority/host, while
/// `fractalforge:/view?...` and `fractalforge:view?...` are path-only forms.
/// Keep those shapes distinct so a non-view authority cannot smuggle a view
/// route through its path (for example `fractalforge://other/view?...`).
class _DeepLinkCustomRouteShape {
  final String host;
  final String path;

  const _DeepLinkCustomRouteShape({
    required this.host,
    required this.path,
  });

  factory _DeepLinkCustomRouteShape.fromUri(Uri uri) {
    return _DeepLinkCustomRouteShape(host: uri.host, path: uri.path);
  }

  bool get hasAuthority => host.isNotEmpty;

  bool get isViewRoute {
    if (hasAuthority) {
      return host == DeepLinkService.host &&
          _DeepLinkViewRoutePath.isAuthorityRoot(path);
    }
    return _DeepLinkViewRoutePath.isPathOnlyCustomSchemeView(path);
  }
}

class _DeepLinkRoute {
  static const allowedWebHosts = {'fractalforge.app', 'www.fractalforge.app'};

  final _DeepLinkRouteKind kind;

  const _DeepLinkRoute._(this.kind);

  bool get isAccepted => kind != _DeepLinkRouteKind.rejected;

  factory _DeepLinkRoute.fromUri(Uri uri) {
    if (uri.scheme == DeepLinkService.scheme) {
      return _DeepLinkRoute._(
        _isCustomViewRoute(uri)
            ? _DeepLinkRouteKind.customSchemeView
            : _DeepLinkRouteKind.rejected,
      );
    }

    if (uri.scheme == 'https' && allowedWebHosts.contains(uri.host)) {
      return _DeepLinkRoute._(
        _isWebViewRoute(uri)
            ? _DeepLinkRouteKind.universalLinkView
            : _DeepLinkRouteKind.rejected,
      );
    }

    return const _DeepLinkRoute._(_DeepLinkRouteKind.rejected);
  }

  static bool _isCustomViewRoute(Uri uri) {
    return _DeepLinkCustomRouteShape.fromUri(uri).isViewRoute;
  }

  static bool _isWebViewRoute(Uri uri) {
    return _DeepLinkViewRoutePath.isAbsoluteViewPath(uri.path);
  }
}

class _DeepLinkModuleId {
  static final RegExp _safePattern = RegExp(r'^[a-z0-9_]+$');

  const _DeepLinkModuleId._();

  static bool isSafe(String moduleId) => _safePattern.hasMatch(moduleId);

  static String requireSafeForBuild(String moduleId) {
    if (!isSafe(moduleId)) {
      throw ArgumentError.value(
        moduleId,
        'moduleId',
        'Deep-link module IDs must match ${_safePattern.pattern}',
      );
    }
    return moduleId;
  }
}

class _DeepLinkQuery {
  static final recognizedNames = {
    'type',
    for (final param in DeepLinkService._allQueryParams) param.name,
  };

  final Map<String, String> _params;

  const _DeepLinkQuery._(this._params);

  factory _DeepLinkQuery.fromUri(Uri uri) {
    final duplicatedRecognizedKeys = uri.queryParametersAll.entries.where(
      (entry) => recognizedNames.contains(entry.key) && entry.value.length > 1,
    );
    if (duplicatedRecognizedKeys.isNotEmpty) {
      throw FormatException(
        'Duplicate deep-link query parameter: '
        '${duplicatedRecognizedKeys.first.key}',
      );
    }

    return _DeepLinkQuery._(uri.queryParameters);
  }

  String? operator [](String name) => _params[name];
}

abstract interface class _DeepLinkQueryParamContract {
  String get name;
}

class _BoundedDoubleQueryParam implements _DeepLinkQueryParamContract {
  @override
  final String name;
  final double min;
  final double max;

  const _BoundedDoubleQueryParam(this.name, this.min, this.max);

  double? parse(_DeepLinkQuery query) {
    return DeepLinkService._parseBoundedDouble(query[name], min, max, name);
  }

  String? format(
    Object? value, {
    bool preservePrecision = false,
    double compactTolerance = 0.0,
  }) {
    final parsed = DeepLinkService._tryFiniteDouble(value);
    if (parsed == null || !_contains(parsed)) {
      return null;
    }
    return DeepLinkService._formatDouble(
      parsed,
      preservePrecision: preservePrecision,
      compactTolerance: compactTolerance,
    );
  }

  bool _contains(double value) => value >= min && value <= max;
}

class _BoundedIntQueryParam implements _DeepLinkQueryParamContract {
  @override
  final String name;
  final int min;
  final int max;

  const _BoundedIntQueryParam(this.name, this.min, this.max);

  int? parse(_DeepLinkQuery query) {
    return DeepLinkService._parseBoundedInt(query[name], min, max, name);
  }

  String? format(Object? value) {
    final parsed = _DeepLinkIntegerValue.tryParseObject(value);
    if (parsed == null || !_contains(parsed)) {
      return null;
    }
    return parsed.toString();
  }

  bool _contains(int value) => value >= min && value <= max;
}

class _DeepLinkIntegerValue {
  static const double _maxSafeIntegerDouble = 9007199254740991.0;

  const _DeepLinkIntegerValue._();

  /// Mirrors runtime module int-param readers for generated and incoming links:
  /// persisted parameter maps and hand-authored URLs may carry slider-originated
  /// doubles, but replay needs integer query values.
  static int? tryParseObject(Object? value) {
    return switch (value) {
      int v => v,
      double v => _roundSafeDouble(v),
      String v => tryParseText(v),
      _ => null,
    };
  }

  static int? tryParseText(String? value) {
    if (value == null) return null;
    return int.tryParse(value) ?? _roundSafeDouble(double.tryParse(value));
  }

  static int? _roundSafeDouble(double? value) {
    if (value == null || !_isSafeIntegerDouble(value)) return null;
    return value.round();
  }

  static bool _isSafeIntegerDouble(double value) {
    return value.isFinite && value.abs() <= _maxSafeIntegerDouble;
  }
}

/// Mapping between public deep-link Julia aliases and runtime module params.
///
/// Share URLs use compact, stable query names (`juliaX`/`juliaY`), while
/// render modules expose controls as `juliaCReal`/`juliaCImag`. Keeping the
/// mapping explicit prevents generated links and applied deep links from
/// silently dropping Julia constants.
class _DeepLinkJuliaConstantParams {
  static const String urlReal = 'juliaX';
  static const String urlImaginary = 'juliaY';
  static const String runtimeReal = 'juliaCReal';
  static const String runtimeImaginary = 'juliaCImag';

  const _DeepLinkJuliaConstantParams._();

  static void addRuntimeParams(
    Map<String, Object> params, {
    required double? real,
    required double? imaginary,
  }) {
    if (real != null) params[runtimeReal] = real;
    if (imaginary != null) params[runtimeImaginary] = imaginary;
  }

  /// Generated links should prefer actual runtime parameter names but still
  /// accept already URL-shaped maps for compatibility with existing callers.
  static Object? realValueForBuild(Map<String, Object> params) {
    return params[runtimeReal] ?? params[urlReal];
  }

  static Object? imaginaryValueForBuild(Map<String, Object> params) {
    return params[runtimeImaginary] ?? params[urlImaginary];
  }
}

class _DeepLinkViewQueryBounds {
  // Mirrors the controller's default minimum zoom so generated links can
  // replay valid zoomed-out views instead of dropping them back to 1.0x.
  static const double minReplayableZoom = 1e-9;

  // Keep the legacy accepted upper cap for inbound links; generated links still
  // omit out-of-range values rather than minting clamped camera state.
  static const double maxAcceptedZoom = 1e15;
  static const double minCoordinate = -1e10;
  static const double maxCoordinate = 1e10;

  const _DeepLinkViewQueryBounds._();
}

class DeepLinkService {
  static const String scheme = 'fractalforge';
  static const String host = 'view';

  static const _zoomParam = _BoundedDoubleQueryParam(
    'zoom',
    _DeepLinkViewQueryBounds.minReplayableZoom,
    _DeepLinkViewQueryBounds.maxAcceptedZoom,
  );
  static const _xParam = _BoundedDoubleQueryParam(
    'x',
    _DeepLinkViewQueryBounds.minCoordinate,
    _DeepLinkViewQueryBounds.maxCoordinate,
  );
  static const _yParam = _BoundedDoubleQueryParam(
    'y',
    _DeepLinkViewQueryBounds.minCoordinate,
    _DeepLinkViewQueryBounds.maxCoordinate,
  );
  static const _rotXParam = _BoundedDoubleQueryParam(
    'rotX',
    _DeepLinkViewQueryBounds.minCoordinate,
    _DeepLinkViewQueryBounds.maxCoordinate,
  );
  static const _rotYParam = _BoundedDoubleQueryParam(
    'rotY',
    _DeepLinkViewQueryBounds.minCoordinate,
    _DeepLinkViewQueryBounds.maxCoordinate,
  );
  static const _rotZParam = _BoundedDoubleQueryParam(
    'rotZ',
    _DeepLinkViewQueryBounds.minCoordinate,
    _DeepLinkViewQueryBounds.maxCoordinate,
  );
  static const _iterationsParam = _BoundedIntQueryParam('iterations', 1, 10000);
  static const _bailoutParam = _BoundedDoubleQueryParam('bailout', 1.0, 1e10);
  static const _colorSchemeParam =
      _BoundedIntQueryParam('colorScheme', 0, 9999);
  static const _powerParam = _BoundedDoubleQueryParam('power', 1, 20);
  static const _juliaXParam = _BoundedDoubleQueryParam(
    _DeepLinkJuliaConstantParams.urlReal,
    -1e10,
    1e10,
  );
  static const _juliaYParam = _BoundedDoubleQueryParam(
    _DeepLinkJuliaConstantParams.urlImaginary,
    -1e10,
    1e10,
  );

  /// Keeps common Vector3 float32 artifacts (for example `0.3` becoming
  /// `0.3000000119`) from leaking into share URLs while still preserving
  /// rotation values where six-decimal formatting would visibly change input.
  static const double _rotationCompactTolerance = 5e-8;

  static const List<_DeepLinkQueryParamContract> _allQueryParams = [
    _zoomParam,
    _xParam,
    _yParam,
    _rotXParam,
    _rotYParam,
    _rotZParam,
    _iterationsParam,
    _bailoutParam,
    _colorSchemeParam,
    _powerParam,
    _juliaXParam,
    _juliaYParam,
  ];

  // Method channel for receiving deep links from native code
  static const MethodChannel _channel =
      MethodChannel('com.fractalforge/deeplink');

  final StreamController<DeepLinkData> _linkController =
      StreamController<DeepLinkData>.broadcast();

  /// Stream of parsed deep link data.
  Stream<DeepLinkData> get linkStream => _linkController.stream;

  DeepLinkData? _initialLink;

  /// The initial deep link that launched the app (if any).
  DeepLinkData? get initialLink => _initialLink;

  /// Initializes the deep link service.
  ///
  /// Sets up listeners for incoming deep links from the platform.
  Future<void> initialize() async {
    // TEMPORARY SAFETY SWITCH (2026-02): deep link channel init causes a black screen
    // on some Samsung S24 devices during startup.
    // User confirmed deep links are not needed for the immediate release.
    // We leave parsing + stream support intact for later re-enable.
    const bool kEnableDeepLinks =
        bool.fromEnvironment('ENABLE_DEEP_LINKS', defaultValue: false);
    if (!kEnableDeepLinks) {
      return;
    }

    // Set up method channel handler for incoming links
    _channel.setMethodCallHandler(_handleMethodCall);

    // Try to get the initial link that launched the app
    try {
      final Object? initialUri = await _channel.invokeMethod('getInitialLink');
      final data = parseIncomingLink(initialUri);
      if (data != null) {
        _initialLink = data;
      }
    } on PlatformException {
      // Platform doesn't support deep links or no initial link
    }
  }

  Future<dynamic> _handleMethodCall(MethodCall call) async {
    if (call.method == 'onDeepLink') {
      final data = parseIncomingLink(call.arguments);
      if (data != null) {
        _linkController.add(data);
      }
    }
  }

  /// Parses a platform-provided deep-link payload into [DeepLinkData].
  ///
  /// Native channels are expected to send URI strings, but malformed payloads
  /// are ignored instead of crashing the method-channel handler.
  static DeepLinkData? parseIncomingLink(
    Object? link, {
    List<String>? validFractalTypes,
  }) {
    if (link is! String || link.isEmpty) {
      return null;
    }

    try {
      return parseUri(
        Uri.parse(link),
        validFractalTypes: validFractalTypes,
      );
    } catch (e) {
      // Malformed URI, ignore.
      if (kDebugMode) debugPrint('Failed to parse deep link URI: $e');
      return null;
    }
  }

  /// Parses a URI into [DeepLinkData].
  ///
  /// Returns null if the URI is not a valid fractalforge deep link or
  /// if the fractal type is not recognized.
  static DeepLinkData? parseUri(Uri uri, {List<String>? validFractalTypes}) {
    final route = _DeepLinkRoute.fromUri(uri);
    if (!route.isAccepted) {
      return null;
    }

    final _DeepLinkQuery query;
    try {
      query = _DeepLinkQuery.fromUri(uri);
    } on FormatException catch (e) {
      if (kDebugMode) debugPrint('DeepLink: ${e.message} — rejecting link');
      return null;
    }

    final type = query['type'];

    if (type == null || type.isEmpty) {
      return null;
    }

    // Reject type strings with unsafe characters (defense-in-depth).
    if (!_DeepLinkModuleId.isSafe(type)) {
      return null;
    }

    // Validate fractal type if validation list provided
    if (validFractalTypes != null && !validFractalTypes.contains(type)) {
      return null;
    }

    return DeepLinkData(
      type: type,
      zoom: _zoomParam.parse(query),
      x: _xParam.parse(query),
      y: _yParam.parse(query),
      rotX: _rotXParam.parse(query),
      rotY: _rotYParam.parse(query),
      rotZ: _rotZParam.parse(query),
      iterations: _iterationsParam.parse(query),
      bailout: _bailoutParam.parse(query),
      colorScheme: _colorSchemeParam.parse(query),
      power: _powerParam.parse(query),
      juliaX: _juliaXParam.parse(query),
      juliaY: _juliaYParam.parse(query),
    );
  }

  /// Builds a shareable deep link URL from the current fractal state.
  ///
  /// The [moduleId] specifies the fractal type, [params] contains the
  /// fractal parameters, and [view] contains the camera/view state.
  static Uri buildUri({
    required String moduleId,
    required Map<String, Object> params,
    required FractalViewState view,
  }) {
    final queryParams = <String, String>{
      'type': _DeepLinkModuleId.requireSafeForBuild(moduleId),
    };

    _addViewStateQueryParams(queryParams, view);

    // Add fractal parameters. Unsupported values are omitted rather than
    // converted to sentinel values that parse back as valid-but-wrong params.
    _addBoundedIntQueryParam(
        queryParams, _iterationsParam, params['iterations']);
    _addBoundedDoubleQueryParam(queryParams, _bailoutParam, params['bailout']);
    _addBoundedIntQueryParam(
      queryParams,
      _colorSchemeParam,
      params['colorScheme'],
    );
    _addBoundedDoubleQueryParam(queryParams, _powerParam, params['power']);
    _addBoundedDoubleQueryParam(
      queryParams,
      _juliaXParam,
      _DeepLinkJuliaConstantParams.realValueForBuild(params),
      preservePrecision: true,
    );
    _addBoundedDoubleQueryParam(
      queryParams,
      _juliaYParam,
      _DeepLinkJuliaConstantParams.imaginaryValueForBuild(params),
      preservePrecision: true,
    );

    return Uri(
      scheme: scheme,
      host: host,
      queryParameters: queryParams,
    );
  }

  /// Adds view-state fields to generated links.
  ///
  /// View state is one replay contract: zoom, pan, and 3D rotation values all
  /// need significant digits preserved so shared links restore the same camera
  /// instead of a rounded approximation.
  static void _addViewStateQueryParams(
    Map<String, String> queryParams,
    FractalViewState view,
  ) {
    // Use the same bounded contracts as parsing so generated links do not
    // round-trip through clamped or invalid camera values.
    _addNonDefaultBoundedDoubleQueryParam(
      queryParams,
      _zoomParam,
      view.zoom,
      defaultValue: 1.0,
      preservePrecision: true,
    );
    _addNonDefaultBoundedDoubleQueryParam(
      queryParams,
      _xParam,
      view.pan.x,
      preservePrecision: true,
    );
    _addNonDefaultBoundedDoubleQueryParam(
      queryParams,
      _yParam,
      view.pan.y,
      preservePrecision: true,
    );
    _addNonDefaultBoundedDoubleQueryParam(
      queryParams,
      _rotXParam,
      view.rotation.x,
      preservePrecision: true,
      compactTolerance: _rotationCompactTolerance,
    );
    _addNonDefaultBoundedDoubleQueryParam(
      queryParams,
      _rotYParam,
      view.rotation.y,
      preservePrecision: true,
      compactTolerance: _rotationCompactTolerance,
    );
    _addNonDefaultBoundedDoubleQueryParam(
      queryParams,
      _rotZParam,
      view.rotation.z,
      preservePrecision: true,
      compactTolerance: _rotationCompactTolerance,
    );
  }

  /// Builds a web-compatible URL for sharing.
  ///
  /// Uses a hypothetical web domain for universal link support.
  static Uri buildWebUri({
    required String moduleId,
    required Map<String, Object> params,
    required FractalViewState view,
  }) {
    final customUri = buildUri(moduleId: moduleId, params: params, view: view);
    return Uri(
      scheme: 'https',
      host: 'fractalforge.app',
      path: '/view',
      queryParameters: customUri.queryParameters,
    );
  }

  static double? _parseBoundedDouble(
      String? v, double min, double max, String paramName) {
    if (v == null) return null;
    final d = double.tryParse(v);
    if (d == null || d.isNaN || d.isInfinite) {
      if (kDebugMode)
        debugPrint('DeepLink: invalid value for "$paramName": "$v" — ignoring');
      return null;
    }
    final clamped = d.clamp(min, max);
    if (clamped != d) {
      if (kDebugMode)
        debugPrint(
            'DeepLink: "$paramName" value $d out of [$min, $max] — clamped to $clamped');
    }
    return clamped;
  }

  static int? _parseBoundedInt(String? v, int min, int max, String paramName) {
    if (v == null) return null;
    final i = _DeepLinkIntegerValue.tryParseText(v);
    if (i == null) {
      if (kDebugMode)
        debugPrint('DeepLink: invalid value for "$paramName": "$v" — ignoring');
      return null;
    }
    final clamped = i.clamp(min, max);
    if (clamped != i) {
      if (kDebugMode)
        debugPrint(
            'DeepLink: "$paramName" value $i out of [$min, $max] — clamped to $clamped');
    }
    return clamped;
  }

  static String _formatDouble(
    double value, {
    bool preservePrecision = false,
    double compactTolerance = 0.0,
  }) {
    // Keep integer-looking values compact without truncating significant deep-zoom
    // view coordinates that need more than six decimal places to round-trip.
    if (value == value.truncateToDouble()) {
      return value.toInt().toString();
    }

    final compactFixed =
        value.toStringAsFixed(6).replaceAll(RegExp(r'\.?0+$'), '');
    final compactValue = double.tryParse(compactFixed);
    final compactWithinTolerance = compactValue != null &&
        compactTolerance > 0.0 &&
        (compactValue - value).abs() <= compactTolerance;
    if (!preservePrecision || compactValue == value || compactWithinTolerance) {
      return compactFixed;
    }

    return value.toString();
  }

  static void _addBoundedDoubleQueryParam(
    Map<String, String> queryParams,
    _BoundedDoubleQueryParam param,
    Object? value, {
    bool preservePrecision = false,
    double compactTolerance = 0.0,
  }) {
    final formatted = param.format(
      value,
      preservePrecision: preservePrecision,
      compactTolerance: compactTolerance,
    );
    if (formatted != null) {
      queryParams[param.name] = formatted;
    }
  }

  static void _addNonDefaultBoundedDoubleQueryParam(
    Map<String, String> queryParams,
    _BoundedDoubleQueryParam param,
    Object? value, {
    double defaultValue = 0.0,
    bool preservePrecision = false,
    double compactTolerance = 0.0,
  }) {
    final parsed = _tryFiniteDouble(value);
    if (parsed == null || parsed == defaultValue) return;
    _addBoundedDoubleQueryParam(
      queryParams,
      param,
      parsed,
      preservePrecision: preservePrecision,
      compactTolerance: compactTolerance,
    );
  }

  static void _addBoundedIntQueryParam(
    Map<String, String> queryParams,
    _BoundedIntQueryParam param,
    Object? value,
  ) {
    final formatted = param.format(value);
    if (formatted != null) {
      queryParams[param.name] = formatted;
    }
  }

  static double? _tryFiniteDouble(Object? value) {
    final parsed = switch (value) {
      double v => v,
      int v => v.toDouble(),
      String v => double.tryParse(v),
      _ => null,
    };
    if (parsed == null || parsed.isNaN || parsed.isInfinite) {
      return null;
    }
    return parsed;
  }

  /// Disposes of the service and closes the stream.
  void dispose() {
    _linkController.close();
  }
}

import 'package:flutter_test/flutter_test.dart';
import 'package:flutter_fractals/core/services/deep_link_service.dart';
import 'package:flutter_fractals/core/models/fractal_view_state.dart';
import 'package:vector_math/vector_math.dart';

void main() {
  group('DeepLinkService', () {
    group('parseIncomingLink', () {
      test('parses string payloads from platform channels', () {
        final data = DeepLinkService.parseIncomingLink(
          'fractalforge://view?type=mandelbrot&zoom=5',
        );

        expect(data, isNotNull);
        expect(data!.type, 'mandelbrot');
        expect(data.zoom, 5.0);
      });

      test('ignores malformed or non-string platform payloads', () {
        expect(DeepLinkService.parseIncomingLink(null), isNull);
        expect(DeepLinkService.parseIncomingLink(42), isNull);
        expect(DeepLinkService.parseIncomingLink(''), isNull);
        expect(
          DeepLinkService.parseIncomingLink('fractalforge://view?type=%'),
          isNull,
        );
      });
    });

    group('parseUri', () {
      test('parses basic fractalforge:// URL', () {
        final uri = Uri.parse('fractalforge://view?type=mandelbrot');
        final data = DeepLinkService.parseUri(uri);

        expect(data, isNotNull);
        expect(data!.type, 'mandelbrot');
      });

      test('parses URL with zoom and pan parameters', () {
        final uri = Uri.parse(
            'fractalforge://view?type=mandelbrot&zoom=10&x=-0.5&y=0.1');
        final data = DeepLinkService.parseUri(uri);

        expect(data, isNotNull);
        expect(data!.type, 'mandelbrot');
        expect(data.zoom, 10.0);
        expect(data.x, -0.5);
        expect(data.y, 0.1);
      });

      test('parses URL with 3D rotation parameters', () {
        final uri = Uri.parse(
            'fractalforge://view?type=mandelbulb&rotX=0.5&rotY=0.3&rotZ=0.1');
        final data = DeepLinkService.parseUri(uri);

        expect(data, isNotNull);
        expect(data!.type, 'mandelbulb');
        expect(data.rotX, 0.5);
        expect(data.rotY, 0.3);
        expect(data.rotZ, 0.1);
      });

      test('parses URL with fractal parameters', () {
        final uri = Uri.parse(
            'fractalforge://view?type=julia&iterations=200&colorScheme=2&juliaX=-0.7&juliaY=0.27');
        final data = DeepLinkService.parseUri(uri);

        expect(data, isNotNull);
        expect(data!.type, 'julia');
        expect(data.iterations, 200);
        expect(data.colorScheme, 2);
        expect(data.juliaX, -0.7);
        expect(data.juliaY, 0.27);
      });

      test('parses decimal integer parameters like generated links do', () {
        final uri = Uri.parse(
          'fractalforge://view?type=mandelbrot&iterations=120.5&colorScheme=2.0',
        );
        final data = DeepLinkService.parseUri(uri);

        expect(data, isNotNull);
        expect(data!.iterations, 121);
        expect(data.colorScheme, 2);
      });

      test('returns null for non-fractalforge scheme', () {
        final uri = Uri.parse('https://example.com/view?type=mandelbrot');
        final data = DeepLinkService.parseUri(uri);

        expect(data, isNull);
      });

      test('returns null for missing type parameter', () {
        final uri = Uri.parse('fractalforge://view?zoom=10');
        final data = DeepLinkService.parseUri(uri);

        expect(data, isNull);
      });

      test('parses https://fractalforge.app universal link', () {
        final uri =
            Uri.parse('https://fractalforge.app/view?type=mandelbrot&zoom=5');
        final data = DeepLinkService.parseUri(uri);

        expect(data, isNotNull);
        expect(data!.type, 'mandelbrot');
        expect(data.zoom, 5.0);
      });

      test('characterizes accepted deep-link route variants', () {
        final acceptedLinks = [
          'fractalforge://view?type=mandelbrot',
          'fractalforge://view/?type=mandelbrot',
          'fractalforge:/view?type=mandelbrot',
          'fractalforge:view?type=mandelbrot',
          'https://fractalforge.app/view?type=mandelbrot',
          'https://fractalforge.app/view/?type=mandelbrot',
          'https://www.fractalforge.app/view?type=mandelbrot',
          'https://www.fractalforge.app/view/?type=mandelbrot',
        ];

        for (final link in acceptedLinks) {
          expect(
            DeepLinkService.parseUri(Uri.parse(link))?.type,
            'mandelbrot',
            reason: link,
          );
        }
      });

      test('rejects custom-scheme route authority/path ambiguity', () {
        final rejectedLinks = [
          'fractalforge://other/view?type=mandelbrot',
          'fractalforge://view/settings?type=mandelbrot',
          'fractalforge://view/view?type=mandelbrot',
        ];

        for (final link in rejectedLinks) {
          expect(
            DeepLinkService.parseUri(Uri.parse(link)),
            isNull,
            reason: link,
          );
        }
      });

      test('rejects https universal links outside the view route', () {
        final uri = Uri.parse(
            'https://fractalforge.app/settings?type=mandelbrot&zoom=5');
        final data = DeepLinkService.parseUri(uri);

        expect(data, isNull);
      });

      test('rejects duplicate recognized parameters instead of guessing', () {
        final uri = Uri.parse(
          'fractalforge://view?type=mandelbrot&type=julia&zoom=5',
        );
        final data = DeepLinkService.parseUri(uri);

        expect(data, isNull);
      });

      test('rejects duplicate optional parameters instead of truncating', () {
        final uri = Uri.parse(
          'fractalforge://view?type=mandelbrot&zoom=5&zoom=abc',
        );
        final data = DeepLinkService.parseUri(uri);

        expect(data, isNull);
      });

      test('ignores duplicate unrecognized parameters', () {
        final uri = Uri.parse(
          'fractalforge://view?type=mandelbrot&utm=a&utm=b&zoom=5',
        );
        final data = DeepLinkService.parseUri(uri);

        expect(data, isNotNull);
        expect(data!.type, 'mandelbrot');
        expect(data.zoom, 5.0);
      });

      test('rejects duplicates for every generated deep-link parameter', () {
        final generated = DeepLinkService.buildUri(
          moduleId: 'julia',
          params: const {
            'iterations': 200,
            'bailout': 4.5,
            'colorScheme': 2,
            'power': 8.0,
            'juliaX': -0.7,
            'juliaY': 0.27,
          },
          view: FractalViewState(
            pan: Vector2(-0.5, 0.25),
            zoom: 5.0,
            rotation: Vector3(0.1, 0.2, 0.3),
          ),
        );

        for (final paramName in generated.queryParameters.keys) {
          final duplicated = generated.replace(
            query: '${generated.query}&$paramName=duplicate',
          );

          expect(
            DeepLinkService.parseUri(duplicated),
            isNull,
            reason: '$paramName must be part of duplicate detection',
          );
        }
      });
    });

    group('buildUri', () {
      test('builds basic URL with type only', () {
        final uri = DeepLinkService.buildUri(
          moduleId: 'mandelbrot',
          params: {},
          view: FractalViewState.initial(),
        );

        expect(uri.scheme, 'fractalforge');
        expect(uri.host, 'view');
        expect(uri.queryParameters['type'], 'mandelbrot');
      });

      test('rejects unsafe module IDs before generating unreplayable links',
          () {
        expect(
          () => DeepLinkService.buildUri(
            moduleId: 'mandelbrot<script>',
            params: const {},
            view: FractalViewState.initial(),
          ),
          throwsArgumentError,
        );
      });

      test('includes zoom when not default', () {
        final uri = DeepLinkService.buildUri(
          moduleId: 'mandelbrot',
          params: {},
          view: FractalViewState(
            pan: Vector2.zero(),
            zoom: 5.0,
            rotation: Vector3.zero(),
          ),
        );

        expect(uri.queryParameters['zoom'], '5');
      });

      test('includes pan coordinates when not zero', () {
        final uri = DeepLinkService.buildUri(
          moduleId: 'mandelbrot',
          params: {},
          view: FractalViewState(
            pan: Vector2(-0.5, 0.25),
            zoom: 1.0,
            rotation: Vector3.zero(),
          ),
        );

        expect(uri.queryParameters['x'], '-0.5');
        expect(uri.queryParameters['y'], '0.25');
      });

      test('includes rotation for 3D fractals', () {
        final uri = DeepLinkService.buildUri(
          moduleId: 'mandelbulb',
          params: {},
          view: FractalViewState(
            pan: Vector2.zero(),
            zoom: 1.0,
            rotation: Vector3(0.5, 0.3, 0.1),
          ),
        );

        expect(uri.queryParameters['rotX'], '0.5');
        expect(uri.queryParameters['rotY'], '0.3');
        expect(uri.queryParameters['rotZ'], '0.1');
      });

      test('includes fractal parameters', () {
        final uri = DeepLinkService.buildUri(
          moduleId: 'mandelbrot',
          params: {
            'iterations': 200,
            'colorScheme': 2,
            'bailout': 4.5,
          },
          view: FractalViewState.initial(),
        );

        expect(uri.queryParameters['iterations'], '200');
        expect(uri.queryParameters['colorScheme'], '2');
        expect(uri.queryParameters['bailout'], '4.5');
      });

      test('uses runtime Julia parameter names when building URL aliases', () {
        final uri = DeepLinkService.buildUri(
          moduleId: 'julia',
          params: {
            'juliaCReal': -0.7,
            'juliaCImag': 0.27015,
          },
          view: FractalViewState.initial(),
        );

        expect(uri.queryParameters['juliaX'], '-0.7');
        expect(uri.queryParameters['juliaY'], '0.27015');
      });

      test('formats finite double-valued integer params like runtime readers',
          () {
        final uri = DeepLinkService.buildUri(
          moduleId: 'mandelbrot',
          params: {
            'iterations': 120.5,
            'colorScheme': 2.0,
          },
          view: FractalViewState.initial(),
        );

        expect(uri.queryParameters['iterations'], '121');
        expect(uri.queryParameters['colorScheme'], '2');
      });

      test('omits unsupported parameter values instead of minting fallbacks',
          () {
        final uri = DeepLinkService.buildUri(
          moduleId: 'mandelbrot',
          params: {
            'iterations': true,
            'colorScheme': Object(),
            'bailout': 'not-a-number',
            'power': double.nan,
            'juliaX': double.infinity,
            'juliaY': false,
          },
          view: FractalViewState.initial(),
        );

        expect(uri.queryParameters.containsKey('iterations'), isFalse);
        expect(uri.queryParameters.containsKey('colorScheme'), isFalse);
