/// Replayable filename contract for exported files.
///
/// Both caller-supplied prefix and fractal type become path-safe filename
/// segments. Empty or fully-unsafe prefixes fall back to `fractal` so the
/// generated filename is never hidden, absolute, or parent-relative.
class ExportFilenameParts {
  final String prefix;
  final ExportFormat format;
  final String? fractalType;
  final int timestampMillis;

  const ExportFilenameParts({
    required this.prefix,
    required this.format,
    required this.timestampMillis,
    this.fractalType,
  });

  String get safePrefix => _sanitizeSegment(prefix, fallback: 'fractal')!;

  String? get safeFractalType {
    final value = fractalType;
    if (value == null) return null;
    return _sanitizeSegment(value, fallback: null);
  }

  String get filename {
    final type = safeFractalType;
    final typePart = type == null ? '' : '_$type';
    return '$safePrefix${typePart}_$timestampMillis.${format.extension}';
  }

  static String? _sanitizeSegment(String value, {required String? fallback}) {
    final sanitized = value
        .trim()
        .toLowerCase()
        .replaceAll(RegExp(r'[^a-z0-9_\-]+'), '_')
        .replaceAll(RegExp(r'_+'), '_')
        .replaceAll(RegExp(r'^[_\-.]+|[_\-.]+$'), '');
    if (sanitized.isEmpty || sanitized == '.' || sanitized == '..') {
      return fallback;
    }
    return sanitized;
  }
}

enum _WallpaperOverlayEdge { top, bottom }

/// Replayable vertical gradient used by wallpaper legibility overlays.
///
/// A one-row overlay should still apply full edge strength. For taller overlays,
/// the outer edge reaches [strength] and the inner edge fades to transparent.
final class _WallpaperOverlayGradient {
  final int imageHeight;
  final double coverage;
  final double strength;
  final _WallpaperOverlayEdge edge;

  const _WallpaperOverlayGradient({
    required this.imageHeight,
    required this.coverage,
    required this.strength,
    required this.edge,
  }) : assert(imageHeight > 0, 'imageHeight must be positive');

  int get overlayHeight =>
      (imageHeight * coverage).round().clamp(1, imageHeight).toInt();

  int get startY =>
      edge == _WallpaperOverlayEdge.top ? 0 : imageHeight - overlayHeight;

  int get endYExclusive =>
      edge == _WallpaperOverlayEdge.top ? overlayHeight : imageHeight;

  int alphaForY(int y) {
    final localY = y - startY;
    final edgeWeight = _edgeWeight(localY);
    return (255 * strength * edgeWeight).round().clamp(0, 255).toInt();
  }

  double _edgeWeight(int localY) {
    if (overlayHeight <= 1) return 1.0;

    final progress = (localY / (overlayHeight - 1)).clamp(0.0, 1.0);
    return switch (edge) {
      _WallpaperOverlayEdge.top => 1.0 - progress,
      _WallpaperOverlayEdge.bottom => progress,
    };
  }
}

class ExportService {
  static const MethodChannel _mediaStoreChannel =
      MethodChannel('fractalforge/media_store');
  const ExportService();

  /// Returns the actual format we can encode today.
  ///
  /// WebP is exposed in the UI, but the current pure-Dart image pipeline
  /// cannot encode WebP yet. We explicitly fall back to PNG so filename,
  /// MIME expectations, and snackbar text stay truthful.
  ExportFormat resolveEffectiveFormat(ExportFormat requested) {
    if (requested == ExportFormat.webp) {
      return ExportFormat.png;
    }
    return requested;
  }

  /// Apply simple legibility overlays for wallpaper usage.
  ///
  /// This keeps the fractal intact while slightly darkening common UI areas.
  Uint8List applyWallpaperStyle(Uint8List pngBytes, {required String style}) {
    try {
      final decoded = img.decodePng(pngBytes);
      if (decoded == null) return pngBytes;

      // style: plain|homeOptimized|lockOptimized
      switch (style) {
        case 'homeOptimized':
          return Uint8List.fromList(
              img.encodePng(_applyBottomGradient(decoded, strength: 0.28)));
        case 'lockOptimized':
          var out = _applyTopGradient(decoded, strength: 0.30);
          out = _applyBottomGradient(out, strength: 0.18);
          return Uint8List.fromList(img.encodePng(out));
        default:
          return pngBytes;
      }
    } catch (_) {
      // If any processing fails, return original bytes.
      return pngBytes;
    }
  }

  img.Image _applyTopGradient(img.Image src, {required double strength}) {
    return _applyVerticalGradient(
      src,
      gradient: _WallpaperOverlayGradient(
        imageHeight: src.height,
        coverage: 0.22,
        strength: strength,
        edge: _WallpaperOverlayEdge.top,
      ),
    );
  }

  img.Image _applyBottomGradient(img.Image src, {required double strength}) {
    return _applyVerticalGradient(
      src,
      gradient: _WallpaperOverlayGradient(
        imageHeight: src.height,
        coverage: 0.28,
        strength: strength,
        edge: _WallpaperOverlayEdge.bottom,
      ),
    );
  }

  img.Image _applyVerticalGradient(
    img.Image src, {
    required _WallpaperOverlayGradient gradient,
  }) {
    final out = img.Image.from(src);

    for (int y = gradient.startY; y < gradient.endYExclusive; y++) {
      final alpha = gradient.alphaForY(y);
      if (alpha == 0) continue;

      for (int x = 0; x < out.width; x++) {
        final p = out.getPixel(x, y);
        // Alpha-blend black over pixel (new image package API).
        final r = _darkenChannel(p.r.toInt(), alpha);
        final g = _darkenChannel(p.g.toInt(), alpha);
        final b = _darkenChannel(p.b.toInt(), alpha);
        out.setPixelRgba(x, y, r, g, b, p.a.toInt());
      }
    }

    return out;
  }

  int _darkenChannel(int value, int alpha) {
    return (value * (255 - alpha) / 255).round();
  }

  Future<Directory> getExportDirectory() async {
    if (!kIsWeb && Platform.isAndroid) {
      // Avoid runtime storage permission prompts. Use app-scoped external
      // pictures dir when available; otherwise fall back to app documents.
      final dirs = await getExternalStorageDirectories(
        type: StorageDirectory.pictures,
      );
      final baseDir = dirs?.isNotEmpty == true ? dirs!.first : null;
      if (baseDir != null) {
        final exportDir = Directory('${baseDir.path}/FlutterFractals');
        if (!await exportDir.exists()) {
          await exportDir.create(recursive: true);
        }
        return exportDir;
      }
    }
    final dir = await getApplicationDocumentsDirectory();
    final exportDir = Directory('${dir.path}/exports');
    if (!await exportDir.exists()) {
      await exportDir.create(recursive: true);
    }
    return exportDir;
  }

  Future<File> createExportFile({required String filename}) async {
    final dir = await getExportDirectory();
    return File('${dir.path}/$filename');
  }

  /// Capture the widget as raw RGBA bytes at the specified pixel ratio
  Future<Uint8List> capturePng(GlobalKey boundaryKey,
      {double pixelRatio = 2.0}) async {
    Object? lastError;

    for (var attempt = 0; attempt < 3; attempt++) {
      try {
        RenderRepaintBoundary? boundary = boundaryKey.currentContext
            ?.findRenderObject() as RenderRepaintBoundary?;
        if (boundary == null) {
          throw StateError('Boundary not found');
        }

        // Defensive: boundary.toImage() can throw if the layer hasn't painted yet.
        if (boundary.debugNeedsPaint) {
          await WidgetsBinding.instance.endOfFrame;
          boundary = boundaryKey.currentContext?.findRenderObject()
              as RenderRepaintBoundary?;
          if (boundary == null) {
            throw StateError('Boundary not found');
          }
        }

        final image = await boundary.toImage(pixelRatio: pixelRatio);
        try {
          final byteData =
              await image.toByteData(format: ui.ImageByteFormat.png);
          if (byteData == null) {
            throw StateError('Failed to encode PNG');
          }
          return byteData.buffer.asUint8List();
        } finally {
          image.dispose();
        }
      } catch (error) {
        lastError = error;
        if (attempt == 2) {
          rethrow;
        }
        await WidgetsBinding.instance.endOfFrame;
      }
    }

    throw StateError('Failed to capture PNG: $lastError');
  }

  /// Capture with advanced options (format, resolution, metadata)
  Future<Uint8List> captureWithOptions(
    GlobalKey boundaryKey, {
    required ExportOptions options,
    required double screenWidth,
    required double screenHeight,
    void Function(double progress)? onProgress,
  }) async {
    onProgress?.call(0.1);

    // Calculate pixel ratio for target resolution
    final pixelRatio = options.calculatePixelRatio(screenWidth, screenHeight);

    // Capture raw PNG from Flutter
    final rawPng = await capturePng(boundaryKey, pixelRatio: pixelRatio);
    onProgress?.call(0.4);

    // Decode the PNG for processing
    final decodedImage = img.decodePng(rawPng);
    if (decodedImage == null) {
      throw StateError('Failed to decode captured image');
    }
    onProgress?.call(0.5);

    // Resize if needed for target resolution
    final targetDims = options.getTargetDimensions(screenWidth, screenHeight);
    img.Image processedImage;

    if (decodedImage.width != targetDims.$1 ||
        decodedImage.height != targetDims.$2) {
      processedImage = img.copyResize(
        decodedImage,
        width: targetDims.$1,
        height: targetDims.$2,
        interpolation: img.Interpolation.cubic,
      );
    } else {
      processedImage = decodedImage;
    }
    onProgress?.call(0.6);

    // Add watermark if requested
    if (options.addWatermark && options.watermarkText != null) {
      processedImage = _addWatermark(processedImage, options.watermarkText!);
    }
    onProgress?.call(0.7);

    // Embed metadata
    if (options.embedMetadata && options.metadata != null) {
      processedImage = _embedMetadata(processedImage, options.metadata!);
    }
    onProgress?.call(0.8);

    // Encode to target format
    final effectiveFormat = resolveEffectiveFormat(options.format);
    final encoded = _encodeToFormat(processedImage, options, effectiveFormat);
    onProgress?.call(1.0);

    return Uint8List.fromList(encoded);
  }

  img.Image _addWatermark(img.Image image, String text) {
    // Simple text watermark in bottom-right corner
    final fontSize = (image.width / 40).round().clamp(12, 48);
    final padding = fontSize;

    img.drawString(
      image,
      text,
      font: img.arial14,
      x: image.width - (text.length * fontSize ~/ 2) - padding,
      y: image.height - fontSize - padding,
      color: img.ColorRgba8(255, 255, 255, 128),
    );

    return image;
  }

  img.Image _embedMetadata(img.Image image, ExportMetadata metadata) {
    // The image package stores metadata in the image object
    // This will be preserved when encoding to formats that support it
    final exifData = metadata.toExifMap();

    // Add metadata as text chunks (supported in PNG)
    for (final entry in exifData.entries) {
      image.textData ??= {};
      image.textData![entry.key] = entry.value;
    }

    return image;
  }

  Uint8List _encodeToFormat(
    img.Image image,
    ExportOptions options,
    ExportFormat effectiveFormat,
  ) {
    switch (effectiveFormat) {
      case ExportFormat.png:
        return Uint8List.fromList(img.encodePng(image, level: 6));

      case ExportFormat.jpg:
        // JPG doesn't support transparency - always composite onto background
        // transparentBackground option is ignored for JPG (use black background)
        final rgbImage = _removeAlpha(image);
        return Uint8List.fromList(
          img.encodeJpg(rgbImage, quality: options.quality),
        );

      case ExportFormat.webp:
        // Guard rail: resolveEffectiveFormat currently maps WebP->PNG.
        return Uint8List.fromList(img.encodePng(image));
    }
  }

  img.Image _removeAlpha(img.Image image) {
    // Create a new RGB image (no alpha channel) for JPG export
    final result = img.Image(
      width: image.width,
      height: image.height,
      numChannels: 3,
    );

    // Fill with black (space around fractals is typically black/transparent)
    img.fill(result, color: img.ColorRgb8(0, 0, 0));

    // Composite the original image over the black background
    img.compositeImage(result, image);

    return result;
  }

  /// Generate a filename with timestamp and format extension
  String generateFilename({
    String prefix = 'fractal',
    required ExportFormat format,
    String? fractalType,
  }) {
    return ExportFilenameParts(
      prefix: prefix,
      format: format,
      fractalType: fractalType,
      timestampMillis: DateTime.now().millisecondsSinceEpoch,
    ).filename;
  }

  Future<File> saveBytes(Uint8List bytes, {required String filename}) async {
    final file = await createExportFile(filename: filename);
    final written = await file.writeAsBytes(bytes, flush: true);
    await _mirrorImageToMediaStoreIfNeeded(bytes, filename);
    return written;
  }

  Future<void> shareFile(File file, {String? text}) async {
    await Share.shareXFiles([XFile(file.path)], text: text);
  }

  bool _isImageFilename(String filename) {
    final lower = filename.toLowerCase();
    return lower.endsWith('.png') ||
        lower.endsWith('.jpg') ||
        lower.endsWith('.jpeg') ||
        lower.endsWith('.gif') ||
        lower.endsWith('.webp');
  }

  String _mimeTypeForFilename(String filename) {
    final lower = filename.toLowerCase();
    if (lower.endsWith('.jpg') || lower.endsWith('.jpeg')) {
      return 'image/jpeg';
    }
    if (lower.endsWith('.webp')) {
      return 'image/webp';
    }
    if (lower.endsWith('.gif')) {
      return 'image/gif';
    }
    return 'image/png';
  }

  Future<void> _mirrorImageToMediaStoreIfNeeded(
    Uint8List bytes,
    String filename,
  ) async {
    if (kIsWeb || !Platform.isAndroid || !_isImageFilename(filename)) {
      return;
    }

    try {
      await _mediaStoreChannel.invokeMethod<String>('saveImage', {
        'bytes': bytes,
        'filename': filename,
        'mimeType': _mimeTypeForFilename(filename),
      });
    } catch (_) {
      // Best-effort only: keep local export path working even if MediaStore fails.
    }
  }

  /// Export with full options and sharing
  Future<ExportResult> exportWithOptions(
    GlobalKey boundaryKey, {
    required ExportOptions options,
    required double screenWidth,
    required double screenHeight,
    required String fractalType,
    required Map<String, Object> parameters,
    void Function(double progress)? onProgress,
  }) async {
    // Create metadata if embedding is enabled
    final metadata = options.embedMetadata
        ? ExportMetadata(
            fractalType: fractalType,
            parameters: parameters,
            createdAt: DateTime.now(),
          )
        : null;

    final effectiveFormat = resolveEffectiveFormat(options.format);

    final finalOptions = options.copyWith(
      metadata: metadata,
      format: effectiveFormat,
    );

    // Capture and process the image
    final bytes = await captureWithOptions(
      boundaryKey,
      options: finalOptions,
      screenWidth: screenWidth,
      screenHeight: screenHeight,
      onProgress: onProgress,
    );

    // Generate filename and save
    final filename = generateFilename(
      format: effectiveFormat,
      fractalType: fractalType,
    );

    final file = await saveBytes(bytes, filename: filename);
    final targetDims =
        finalOptions.getTargetDimensions(screenWidth, screenHeight);

    return ExportResult(
      file: file,
      format: effectiveFormat,
      width: targetDims.$1,
      height: targetDims.$2,
      fileSize: bytes.length,
    );
  }
}

/// Result of an export operation
class ExportResult {
  final File file;
  final ExportFormat format;
  final int width;
  final int height;
  final int fileSize;

  const ExportResult({
    required this.file,
    required this.format,
    required this.width,
    required this.height,
    required this.fileSize,
  });

  String get formattedSize {
    if (fileSize < 1024) {
      return '$fileSize B';
    } else if (fileSize < 1024 * 1024) {
      return '${(fileSize / 1024).toStringAsFixed(1)} KB';
    } else {
      return '${(fileSize / (1024 * 1024)).toStringAsFixed(1)} MB';
    }
  }

  String get resolution => '$width×$height';
}

import 'dart:typed_data';

import 'package:flutter_fractals/core/modules/fractal_module.dart';
import 'package:flutter_fractals/core/services/renderer_settings_service.dart';
import 'package:flutter_fractals/features/renderer/backend_policy.dart';
import 'package:flutter_fractals/features/renderer/render_validation.dart';
import 'package:flutter_test/flutter_test.dart';

void main() {
  group('RendererBackendPolicy', () {
    const policy = RendererBackendPolicy();

    test('prefers GPU on healthy target', () {
      final decision = policy.decide(
        const BackendPolicyInput(
          isAndroid: false,
          isWeb: false,
          isEmulator: false,
          userMode: RendererBackendMode.auto,
          gpuHealthFailed: false,
          deepZoomNeedsCpu: false,
          dimension: FractalDimension.twoD,
        ),
      );

      expect(decision.backend, RendererBackend.gpu);
      expect(decision.reasonCode, FallbackReasonCode.none);
    });

    test('uses GPU on healthy android emulator in auto mode', () {
      final decision = policy.decide(
        const BackendPolicyInput(
          isAndroid: true,
          isWeb: false,
          isEmulator: true,
          userMode: RendererBackendMode.auto,
          gpuHealthFailed: false,
          deepZoomNeedsCpu: false,
          dimension: FractalDimension.twoD,
        ),
      );

      expect(decision.backend, RendererBackend.gpu);
      expect(decision.reasonCode, FallbackReasonCode.none);
    });

    test('falls back to CPU on android emulator when GPU health fails', () {
      final decision = policy.decide(
        const BackendPolicyInput(
          isAndroid: true,
          isWeb: false,
          isEmulator: true,
          userMode: RendererBackendMode.auto,
          gpuHealthFailed: true,
          deepZoomNeedsCpu: false,
          dimension: FractalDimension.twoD,
        ),
      );

      expect(decision.backend, RendererBackend.cpu);
      expect(decision.reasonCode, FallbackReasonCode.gpuHealthCheckFailed);
      expect(decision.reasonToken, 'gpu_health_check_failed');
    });

    test('keeps 3D modules on GPU in auto mode', () {
      final decision = policy.decide(
        const BackendPolicyInput(
          isAndroid: true,
          isWeb: false,
          isEmulator: false,
          userMode: RendererBackendMode.auto,
          gpuHealthFailed: true,
          deepZoomNeedsCpu: false,
          dimension: FractalDimension.threeD,
        ),
      );

      expect(decision.backend, RendererBackend.gpu);
      expect(decision.reasonCode, FallbackReasonCode.none);
    });
  });

  group('Render validation', () {
    test('detects non-black histogram and progression', () {
      final frameA = Uint8List.fromList(List<int>.filled(16 * 4, 0));
      final frameB = Uint8List.fromList(List<int>.filled(16 * 4, 0));

      // center pixel (1,1) for a 4x4 image
      const center = (1 * 4 + 1) * 4;
      frameB[center] = 64;
      frameB[center + 1] = 96;
      frameB[center + 2] = 128;

      // add additional non-black + changed pixels
      for (int i = 0; i < frameB.length; i += 8) {
        frameB[i] = 32;
        frameB[i + 1] = 16;
        frameB[i + 2] = 48;
      }

      final result = validateRenderPair(
        frameA: frameA,
        frameB: frameB,
        width: 4,
        height: 4,
      );

      expect(result.centerNonBlack, isTrue);
      expect(result.histogramSane, isTrue);
      expect(result.frameProgressed, isTrue);
      expect(result.iterationDeltaVisible, isTrue);
    });
  });
}

import 'package:flutter_fractals/core/modules/fractal_module.dart';
import 'package:flutter_fractals/core/services/renderer_settings_service.dart';
import 'package:flutter_fractals/features/renderer/backend_policy.dart';
import 'package:flutter_test/flutter_test.dart';

void main() {
  const policy = RendererBackendPolicy();

  // Helper to build a standard 2D auto input with overrides.
  BackendPolicyInput buildInput({
    bool isAndroid = false,
    bool isWeb = false,
    bool isEmulator = false,
    RendererBackendMode userMode = RendererBackendMode.auto,
    bool gpuHealthFailed = false,
    bool deepZoomNeedsCpu = false,
    FractalDimension dimension = FractalDimension.twoD,
  }) {
    return BackendPolicyInput(
      isAndroid: isAndroid,
      isWeb: isWeb,
      isEmulator: isEmulator,
      userMode: userMode,
      gpuHealthFailed: gpuHealthFailed,
      deepZoomNeedsCpu: deepZoomNeedsCpu,
      dimension: dimension,
    );
  }

  group('cpuOnly user mode', () {
    test('cpuOnly always returns cpu backend for 2D', () {
      final decision =
          policy.decide(buildInput(userMode: RendererBackendMode.cpuOnly));
      expect(decision.backend, RendererBackend.cpu);
      expect(decision.reasonCode, FallbackReasonCode.manualToggle);
    });

    test('cpuOnly on non-emulator non-android still returns cpu', () {
      final decision = policy.decide(buildInput(
        isAndroid: false,
        isEmulator: false,
        userMode: RendererBackendMode.cpuOnly,
      ));
      expect(decision.backend, RendererBackend.cpu);
    });

    test('cpuOnly with gpuHealthFailed still returns cpu via manualToggle', () {
      // cpuOnly is evaluated before health-check; reason should be manualToggle
      final decision = policy.decide(buildInput(
        userMode: RendererBackendMode.cpuOnly,
        gpuHealthFailed: true,
      ));
      expect(decision.backend, RendererBackend.cpu);
      expect(decision.reasonCode, FallbackReasonCode.manualToggle);
    });

    test('cpuOnly is ignored for 3D module — GPU required', () {
      final decision = policy.decide(buildInput(
        userMode: RendererBackendMode.cpuOnly,
        dimension: FractalDimension.threeD,
      ));
      // 3D always uses GPU; cpuOnly is overridden
      expect(decision.backend, RendererBackend.gpu);
      expect(decision.reasonCode, FallbackReasonCode.moduleUnsupported);
    });
  });

  group('gpuOnly user mode', () {
    test('gpuOnly always returns gpu backend for 2D', () {
      final decision =
          policy.decide(buildInput(userMode: RendererBackendMode.gpuOnly));
      expect(decision.backend, RendererBackend.gpu);
      expect(decision.reasonCode, FallbackReasonCode.manualToggle);
    });

    test('gpuOnly bypasses deep-zoom CPU fallback', () {
      // gpuOnly is evaluated before deepZoomNeedsCpu check
      final decision = policy.decide(buildInput(
        userMode: RendererBackendMode.gpuOnly,
        deepZoomNeedsCpu: true,
      ));
      expect(decision.backend, RendererBackend.gpu);
      expect(decision.reasonCode, FallbackReasonCode.manualToggle);
    });

    test('gpuOnly bypasses GPU health check', () {
      final decision = policy.decide(buildInput(
        userMode: RendererBackendMode.gpuOnly,
        gpuHealthFailed: true,
      ));
      expect(decision.backend, RendererBackend.gpu);
      expect(decision.reasonCode, FallbackReasonCode.manualToggle);
    });
  });

  group('deep zoom CPU fallback', () {
    test('deepZoomNeedsCpu triggers cpu backend in auto mode', () {
      final decision = policy.decide(buildInput(deepZoomNeedsCpu: true));
      expect(decision.backend, RendererBackend.cpu);
      expect(decision.reasonCode, FallbackReasonCode.deepZoomPrecision);
    });

    test('deepZoomNeedsCpu reasonToken is deep_zoom_precision', () {
      final decision = policy.decide(buildInput(deepZoomNeedsCpu: true));
      expect(decision.reasonToken, 'deep_zoom_precision');
    });

    test('deepZoomNeedsCpu is evaluated after gpuHealthFailed', () {
      // gpuHealthFailed is checked first in the policy
      final decision = policy.decide(buildInput(
        gpuHealthFailed: true,
        deepZoomNeedsCpu: true,
      ));
      expect(decision.backend, RendererBackend.cpu);
      expect(decision.reasonCode, FallbackReasonCode.gpuHealthCheckFailed);
    });
  });

  group('GPU health failure', () {
    test('GPU health failure in auto mode returns cpu', () {
      final decision = policy.decide(buildInput(gpuHealthFailed: true));
      expect(decision.backend, RendererBackend.cpu);
      expect(decision.reasonCode, FallbackReasonCode.gpuHealthCheckFailed);
    });

    test('combined emulator + GPU health fail returns cpu', () {
      final decision = policy.decide(buildInput(
        isAndroid: true,
        isEmulator: true,
        gpuHealthFailed: true,
      ));
      expect(decision.backend, RendererBackend.cpu);
      expect(decision.reasonCode, FallbackReasonCode.gpuHealthCheckFailed);
    });

    test('isFallback is true when backend is cpu', () {
      final decision = policy.decide(buildInput(gpuHealthFailed: true));
      expect(decision.isFallback, isTrue);
    });
  });

  group('policy explanation', () {
    test('exposes selected rule while preserving decide compatibility', () {
      final resolution = policy.explain(buildInput(gpuHealthFailed: true));

      expect(resolution.selectedRule, 'gpu_health_failed');
      expect(resolution.platformSignalsUsed, isFalse);
      expect(resolution.decision.backend, RendererBackend.cpu);
      expect(policy.decide(buildInput(gpuHealthFailed: true)).reasonCode,
          resolution.decision.reasonCode);
    });

    test('documents platform signals as advisory in auto mode', () {
      final emulatorResolution = policy.explain(buildInput(
        isAndroid: true,
        isEmulator: true,
      ));
      final webResolution = policy.explain(buildInput(isWeb: true));

      expect(emulatorResolution.selectedRule, 'healthy_gpu_target');
      expect(emulatorResolution.platformSignalsUsed, isFalse);
      expect(webResolution.selectedRule, 'healthy_gpu_target');
      expect(webResolution.platformSignalsUsed, isFalse);
    });
  });

  group('healthy GPU with auto mode', () {
    test('healthy GPU with auto mode returns gpu', () {
      final decision = policy.decide(buildInput());
      expect(decision.backend, RendererBackend.gpu);
      expect(decision.reasonCode, FallbackReasonCode.none);
    });

    test('isFallback is false for gpu decision', () {
      final decision = policy.decide(buildInput());
      expect(decision.isFallback, isFalse);
    });

    test('reasonToken is none for healthy GPU', () {
      final decision = policy.decide(buildInput());
      expect(decision.reasonToken, 'none');
    });

    test('toUserStatusText returns GPU label on healthy path', () {
      final decision = policy.decide(buildInput());
      expect(decision.toUserStatusText(), 'Renderer: GPU');
    });
  });

  group('3D module (unsupported GPU override)', () {
    test('3D module with auto mode uses GPU', () {
      final decision =
          policy.decide(buildInput(dimension: FractalDimension.threeD));
      expect(decision.backend, RendererBackend.gpu);
    });

    test('cpuOnly is ignored for 3D — moduleUnsupported reason', () {
      final decision = policy.decide(buildInput(
        userMode: RendererBackendMode.cpuOnly,
        dimension: FractalDimension.threeD,
      ));
      expect(decision.backend, RendererBackend.gpu);
      expect(decision.reasonCode, FallbackReasonCode.moduleUnsupported);
      expect(decision.reasonToken, 'module_unsupported');
    });

    test('3D module toUserStatusText returns GPU label (backend is gpu)', () {
      final decision = policy.decide(buildInput(
        userMode: RendererBackendMode.cpuOnly,
        dimension: FractalDimension.threeD,
      ));
      // backend == gpu so isFallback is false; toUserStatusText returns 'Renderer: GPU'
      // regardless of reasonCode because the !isFallback check fires first.
      expect(decision.backend, RendererBackend.gpu);
      expect(decision.isFallback, isFalse);
      expect(decision.toUserStatusText(), 'Renderer: GPU');
    });
  });

  group('AndroidEmulatorSignals', () {
    test('classifies each emulator marker without IO', () {
      const samples = [
        AndroidEmulatorSignals(cpuInfo: 'Hardware\t: ranchu'),
        AndroidEmulatorSignals(
            cpuInfo: 'Processor\t: Android Virtual Processor'),
        AndroidEmulatorSignals(cpuInfo: 'vendor_id\t: QEMU'),
        AndroidEmulatorSignals(hardware: ' goldfish\n'),
        AndroidEmulatorSignals(buildCharacteristics: 'nosdcard,emulator'),
        AndroidEmulatorSignals(productModel: 'sdk_gphone64_x86_64'),
        AndroidEmulatorSignals(productModel: 'Android SDK built for x86'),
        AndroidEmulatorSignals(buildProp: 'ro.hardware=ranchu\n'),
        AndroidEmulatorSignals(buildProp: 'ro.product.cpu.abi=generic_x86'),
      ];

      for (final sample in samples) {
        expect(sample.isEmulator, isTrue);
      }
    });

    test('does not classify physical-device-looking signals as emulator', () {
      const signals = AndroidEmulatorSignals(
        cpuInfo: 'Hardware\t: Qualcomm Technologies',
        hardware: 'qcom',
        buildCharacteristics: 'default',
        productModel: 'Pixel 8',
        buildProp: 'ro.hardware=qcom\nro.product.model=Pixel 8\n',
      );

      expect(signals.isEmulator, isFalse);
    });
  });

  group('BackendDecision helpers', () {
    test('toLogLine contains backend, reason, module, and detail', () {
      const decision = BackendDecision(
        backend: RendererBackend.cpu,
        reasonCode: FallbackReasonCode.deepZoomPrecision,
        detail: 'deep_zoom_precision_policy',
      );
      final line = decision.toLogLine(moduleId: 'mandelbrot');
      expect(line, contains('backend=cpu'));
      expect(line, contains('reason=deep_zoom_precision'));
      expect(line, contains('module=mandelbrot'));
      expect(line, contains('detail=deep_zoom_precision_policy'));
    });

    test('toUserStatusText for deep zoom precision', () {
      const decision = BackendDecision(
        backend: RendererBackend.cpu,
        reasonCode: FallbackReasonCode.deepZoomPrecision,
        detail: '',
      );
      expect(decision.toUserStatusText(), 'Deep zoom precision mode enabled');
    });

    test('toUserStatusText for manual toggle cpu', () {
      const decision = BackendDecision(
        backend: RendererBackend.cpu,
        reasonCode: FallbackReasonCode.manualToggle,
        detail: 'cpu_only',
      );
      expect(decision.toUserStatusText(), 'Renderer preference applied');
    });

    test('toUserStatusText for forced by flag', () {
      const decision = BackendDecision(
        backend: RendererBackend.cpu,
        reasonCode: FallbackReasonCode.forcedByFlag,
        detail: '',
      );
      expect(
          decision.toUserStatusText(), 'Stable renderer forced by launch flag');
    });
  });
}

import 'dart:io';

import 'package:flutter/foundation.dart';
import 'package:flutter_fractals/core/modules/fractal_module.dart';
import 'package:flutter_fractals/core/services/renderer_settings_service.dart';

const bool kForceCpuFallback =
    bool.fromEnvironment('FORCE_CPU_FALLBACK', defaultValue: false);
// Android emulator GPU is allowed in auto mode. Runtime health probes in
// FractalViewerScreen enforce fast fallback to CPU on invalid output.

enum RendererBackend { gpu, cpu }

enum FallbackReasonCode {
  none,
  forcedByFlag,
  androidEmulator,
  gpuHealthCheckFailed,
  deepZoomPrecision,
  manualToggle,
  moduleUnsupported,
}

class BackendDecision {
  final RendererBackend backend;
  final FallbackReasonCode reasonCode;
  final String detail;

  const BackendDecision({
    required this.backend,
    required this.reasonCode,
    required this.detail,
  });

  bool get isFallback => backend == RendererBackend.cpu;

  String get reasonToken {
    switch (reasonCode) {
      case FallbackReasonCode.none:
        return 'none';
      case FallbackReasonCode.forcedByFlag:
        return 'forced_by_flag';
      case FallbackReasonCode.androidEmulator:
        return 'android_emulator';
      case FallbackReasonCode.gpuHealthCheckFailed:
        return 'gpu_health_check_failed';
      case FallbackReasonCode.deepZoomPrecision:
        return 'deep_zoom_precision';
      case FallbackReasonCode.manualToggle:
        return 'manual_toggle';
      case FallbackReasonCode.moduleUnsupported:
        return 'module_unsupported';
    }
  }

  String toLogLine({required String moduleId}) {
    return '[renderer] backend_decision backend=${backend.name} reason=$reasonToken module=$moduleId detail=$detail';
  }

  String toUserStatusText() {
    if (!isFallback) return 'Renderer: GPU';
    switch (reasonCode) {
      case FallbackReasonCode.androidEmulator:
        return 'Using stable renderer for this Android emulator';
      case FallbackReasonCode.gpuHealthCheckFailed:
        return 'GPU output unavailable, using stable renderer';
      case FallbackReasonCode.deepZoomPrecision:
        return 'Deep zoom precision mode enabled';
      case FallbackReasonCode.manualToggle:
        return 'Renderer preference applied';
      case FallbackReasonCode.moduleUnsupported:
        return 'Stable renderer enabled for this fractal mode';
      case FallbackReasonCode.forcedByFlag:
        return 'Stable renderer forced by launch flag';
      case FallbackReasonCode.none:
        return 'Renderer: CPU';
    }
  }
}

class BackendPolicyInput {
  final bool isAndroid;
  final bool isWeb;
  final bool isEmulator;
  final RendererBackendMode userMode;
  final bool gpuHealthFailed;
  final bool deepZoomNeedsCpu;
  final FractalDimension dimension;

  const BackendPolicyInput({
    required this.isAndroid,
    required this.isWeb,
    required this.isEmulator,
    required this.userMode,
    required this.gpuHealthFailed,
    required this.deepZoomNeedsCpu,
    required this.dimension,
  });
}

/// Replayable explanation for the backend rule selected by the policy.
///
/// Platform probes are currently advisory in auto mode: Android emulator status
/// is logged and passed through, but runtime health checks decide fallback.
/// Keeping the selected rule visible makes that precedence testable instead of
/// hiding it in early returns.
class BackendPolicyResolution {
  final BackendDecision decision;
  final String selectedRule;
  final bool platformSignalsUsed;

  const BackendPolicyResolution({
    required this.decision,
    required this.selectedRule,
    required this.platformSignalsUsed,
  });
}

class RendererBackendPolicy {
  const RendererBackendPolicy();

  BackendDecision decide(BackendPolicyInput input) => explain(input).decision;

  BackendPolicyResolution explain(BackendPolicyInput input) {
    if (kForceCpuFallback) {
      return const BackendPolicyResolution(
        selectedRule: 'force_cpu_flag',
        platformSignalsUsed: false,
        decision: BackendDecision(
          backend: RendererBackend.cpu,
          reasonCode: FallbackReasonCode.forcedByFlag,
          detail: 'FORCE_CPU_FALLBACK=true',
        ),
      );
    }

    if (input.dimension != FractalDimension.twoD) {
      // 3D modules (e.g. Mandelbulb/Mandelbox) currently rely on GPU shader
      // rendering. Forcing CPU here only produces a disabled placeholder pane.
      // Keep these modules on GPU by default.
      if (input.userMode == RendererBackendMode.cpuOnly) {
        return const BackendPolicyResolution(
          selectedRule: 'gpu_required_module_cpu_only_ignored',
          platformSignalsUsed: false,
          decision: BackendDecision(
            backend: RendererBackend.gpu,
            reasonCode: FallbackReasonCode.moduleUnsupported,
            detail: 'cpu_only_ignored_for_3d_gpu_required',
          ),
        );
      }
      return const BackendPolicyResolution(
        selectedRule: 'gpu_required_module',
        platformSignalsUsed: false,
        decision: BackendDecision(
          backend: RendererBackend.gpu,
          reasonCode: FallbackReasonCode.none,
          detail: '3d_gpu_path',
        ),
      );
    }

    if (input.userMode == RendererBackendMode.cpuOnly) {
      return const BackendPolicyResolution(
        selectedRule: 'manual_cpu_only',
        platformSignalsUsed: false,
        decision: BackendDecision(
          backend: RendererBackend.cpu,
          reasonCode: FallbackReasonCode.manualToggle,
          detail: 'cpu_only',
        ),
      );
    }

    if (input.userMode == RendererBackendMode.gpuOnly) {
      return const BackendPolicyResolution(
        selectedRule: 'manual_gpu_only',
        platformSignalsUsed: false,
        decision: BackendDecision(
          backend: RendererBackend.gpu,
          reasonCode: FallbackReasonCode.manualToggle,
          detail: 'gpu_only',
        ),
      );
    }

    // Emulator targets are handled like physical devices in auto mode.
    // Runtime GPU health checks own fallback decisions.

    if (input.gpuHealthFailed) {
      return const BackendPolicyResolution(
        selectedRule: 'gpu_health_failed',
        platformSignalsUsed: false,
        decision: BackendDecision(
          backend: RendererBackend.cpu,
          reasonCode: FallbackReasonCode.gpuHealthCheckFailed,
          detail: 'frame_probe_detected_invalid_gpu_output',
        ),
      );
    }

    if (input.deepZoomNeedsCpu) {
      return const BackendPolicyResolution(
        selectedRule: 'deep_zoom_precision',
        platformSignalsUsed: false,
        decision: BackendDecision(
          backend: RendererBackend.cpu,
          reasonCode: FallbackReasonCode.deepZoomPrecision,
          detail: 'deep_zoom_precision_policy',
        ),
      );
    }

    return const BackendPolicyResolution(
      selectedRule: 'healthy_gpu_target',
      platformSignalsUsed: false,
      decision: BackendDecision(
        backend: RendererBackend.gpu,
        reasonCode: FallbackReasonCode.none,
        detail: 'healthy_gpu_target',
      ),
    );
  }
}

/// Replayable Android emulator signal snapshot.
///
/// Device probing is intentionally best-effort and IO-heavy; keeping the
/// signal classifier pure makes marker drift testable without touching
/// `/proc`, `getprop`, or `/system` in unit tests.
class AndroidEmulatorSignals {
  final String cpuInfo;
  final String hardware;
  final String buildCharacteristics;
  final String productModel;
  final String buildProp;

  const AndroidEmulatorSignals({
    this.cpuInfo = '',
    this.hardware = '',
    this.buildCharacteristics = '',
    this.productModel = '',
    this.buildProp = '',
  });

  bool get isEmulator =>
      AndroidEmulatorMarkerCatalog.hasCpuInfoMarker(cpuInfo) ||
      AndroidEmulatorMarkerCatalog.hasHardwareMarker(hardware) ||
      AndroidEmulatorMarkerCatalog.hasBuildCharacteristicsMarker(
        buildCharacteristics,
      ) ||
      AndroidEmulatorMarkerCatalog.hasProductModelMarker(productModel) ||
      AndroidEmulatorMarkerCatalog.hasBuildPropMarker(buildProp);
}

/// Named emulator marker contract used by Android emulator signal detection.
///
/// The markers are intentionally conservative: substring checks are used only
/// for fields that can contain labels or full property files, while the direct
/// `ro.hardware` value must match a known virtual hardware token exactly.
class AndroidEmulatorMarkerCatalog {
  static const List<String> cpuInfoSubstrings = [
    'ranchu',
    'goldfish',
    'qemu',
    'android virtual processor',
  ];
  static const List<String> exactHardwareValues = ['ranchu', 'goldfish'];
  static const List<String> buildCharacteristicsSubstrings = ['emulator'];
  static const List<String> productModelSubstrings = [
    'sdk_gphone',
    'android sdk built for',
  ];
  static const List<String> buildPropSubstrings = [
    'ro.hardware=goldfish',
    'ro.hardware=ranchu',
    'sdk_gphone',
    'generic_x86',
  ];

  const AndroidEmulatorMarkerCatalog._();

  static bool hasCpuInfoMarker(String value) {
    return _containsAny(value, cpuInfoSubstrings);
  }

  static bool hasHardwareMarker(String value) {
    return exactHardwareValues.contains(value.trim().toLowerCase());
  }

  static bool hasBuildCharacteristicsMarker(String value) {
    return _containsAny(value, buildCharacteristicsSubstrings);
  }

  static bool hasProductModelMarker(String value) {
    return _containsAny(value, productModelSubstrings);
  }

  static bool hasBuildPropMarker(String value) {
    return _containsAny(value, buildPropSubstrings);
  }

  static bool _containsAny(String value, List<String> markers) {
    final normalized = value.toLowerCase();
    return markers.any(normalized.contains);
  }
}

Future<bool> detectAndroidEmulator() async {
  if (kIsWeb || !Platform.isAndroid) return false;

  var signals = const AndroidEmulatorSignals();

  // 1. /proc/cpuinfo — check for emulator markers
  try {
    signals = AndroidEmulatorSignals(
      cpuInfo: await File('/proc/cpuinfo').readAsString(),
    );
    if (signals.isEmulator) return true;
  } catch (e) {
    if (kDebugMode) debugPrint('[FF] silent catch: $e');
  }

  // 2. getprop — most reliable on modern emulators
  try {
    final result = await Process.run('getprop', ['ro.hardware']);
    signals = AndroidEmulatorSignals(hardware: result.stdout as String);
    if (signals.isEmulator) return true;
  } catch (e) {
    if (kDebugMode) debugPrint('[FF] silent catch: $e');
  }

  try {
    final result = await Process.run('getprop', ['ro.build.characteristics']);
    signals = AndroidEmulatorSignals(
      buildCharacteristics: result.stdout as String,
    );
    if (signals.isEmulator) return true;
  } catch (e) {
    if (kDebugMode) debugPrint('[FF] silent catch: $e');
  }

  try {
    final result = await Process.run('getprop', ['ro.product.model']);
    signals = AndroidEmulatorSignals(productModel: result.stdout as String);
    if (signals.isEmulator) return true;
  } catch (e) {
    if (kDebugMode) debugPrint('[FF] silent catch: $e');
  }

  // 3. /system/build.prop — fallback file check
  try {
    signals = AndroidEmulatorSignals(
      buildProp: await File('/system/build.prop').readAsString(),
    );
    if (signals.isEmulator) return true;
  } catch (e) {
    if (kDebugMode) debugPrint('[FF] silent catch: $e');
  }

  return false;
}

import 'dart:math' as math;
import 'dart:typed_data';

const int _rgbaStride = 4;

/// Numeric thresholds used by render-health probes.
///
/// Keeping these cutoffs in one value object makes the pass/fail contract
/// replayable from tests instead of scattering magic constants through the
/// frame and pair validators.
class RenderValidationThresholds {
  final int blackThreshold;
  final int differenceThreshold;
  final double minimumNonBlackRatio;
  final double minimumProgressionRatio;
  final double minimumIterationDeltaRatio;

  static const defaults = RenderValidationThresholds();

  const RenderValidationThresholds({
    this.blackThreshold = 8,
    this.differenceThreshold = 12,
    this.minimumNonBlackRatio = 0.01,
    this.minimumProgressionRatio = 0.002,
    this.minimumIterationDeltaRatio = 0.01,
  })  : assert(blackThreshold >= 0),
        assert(differenceThreshold >= 0),
        assert(minimumNonBlackRatio >= 0.0),
        assert(minimumProgressionRatio >= 0.0),
        assert(minimumIterationDeltaRatio >= 0.0);

  bool isNonBlackPixel(int r, int g, int b) =>
      r > blackThreshold || g > blackThreshold || b > blackThreshold;

  bool isVisiblyDifferent({
    required int rA,
    required int gA,
    required int bA,
    required int rB,
    required int gB,
    required int bB,
  }) {
    final dr = (rB - rA).abs();
    final dg = (gB - gA).abs();
    final db = (bB - bA).abs();
    return dr + dg + db > differenceThreshold;
  }

  bool histogramSaneFor(double nonBlackRatio) =>
      nonBlackRatio > minimumNonBlackRatio;

  bool frameProgressedFor(double progressionRatio) =>
      progressionRatio > minimumProgressionRatio;

  bool iterationDeltaVisibleFor(double progressionRatio) =>
      progressionRatio > minimumIterationDeltaRatio;
}

class _RenderFrameGeometry {
  final int width;
  final int height;
  final int totalPixels;
  final int centerIndex;

  const _RenderFrameGeometry._({
    required this.width,
    required this.height,
    required this.totalPixels,
    required this.centerIndex,
  });

  factory _RenderFrameGeometry({required int width, required int height}) {
    if (width <= 0 || height <= 0) {
      return _RenderFrameGeometry._(
        width: width,
        height: height,
        totalPixels: 0,
        centerIndex: -1,
      );
    }

    final totalPixels = width * height;
    final cx = (width / 2).floor();
    final cy = (height / 2).floor();
    return _RenderFrameGeometry._(
      width: width,
      height: height,
      totalPixels: totalPixels,
      centerIndex: (cy * width + cx) * _rgbaStride,
    );
  }

  bool canReadCenter(Uint8List frame) =>
      centerIndex >= 0 && centerIndex + 2 < frame.length;

  int readablePixelCount(Uint8List frame) =>
      math.min(totalPixels, frame.length ~/ _rgbaStride);

  bool hasCompleteFrame(Uint8List frame) =>
      totalPixels > 0 && readablePixelCount(frame) == totalPixels;
}

bool _isNonBlack(Uint8List frame, int index) =>
    RenderValidationThresholds.defaults.isNonBlackPixel(
      frame[index],
      frame[index + 1],
      frame[index + 2],
    );

bool _isVisiblyDifferent(Uint8List frameA, Uint8List frameB, int index) =>
    RenderValidationThresholds.defaults.isVisiblyDifferent(
      rA: frameA[index],
      gA: frameA[index + 1],
      bA: frameA[index + 2],
      rB: frameB[index],
      gB: frameB[index + 1],
      bB: frameB[index + 2],
    );

int _countNonBlackPixels(Uint8List frame, int readablePixels) {
  int nonBlack = 0;
  for (int pixel = 0; pixel < readablePixels; pixel++) {
    final i = pixel * _rgbaStride;
    if (_isNonBlack(frame, i)) {
      nonBlack++;
    }
  }
  return nonBlack;
}

int _countDifferentPixels({
  required Uint8List frameA,
  required Uint8List frameB,
  required int readablePixels,
}) {
  int different = 0;
  for (int pixel = 0; pixel < readablePixels; pixel++) {
    final i = pixel * _rgbaStride;
    if (_isVisiblyDifferent(frameA, frameB, i)) {
      different++;
    }
  }
  return different;
}

/// Replayable center-pixel read used by render validation.
///
/// Center sampling is shared by single-frame and pair validators. Exposing the
/// read separately makes the odd/even center convention and truncated-frame
/// fallback replayable without inferring it from final pass/fail booleans.
class RenderCenterSample {
  final int r;
  final int g;
  final int b;
  final bool readable;
  final bool nonBlack;

  const RenderCenterSample({
    required this.r,
    required this.g,
    required this.b,
    required this.readable,
    required this.nonBlack,
  });

  const RenderCenterSample.unreadable()
      : r = 0,
        g = 0,
        b = 0,
        readable = false,
        nonBlack = false;
}

/// Replayable counters used by frame validation.
///
/// This separates byte-buffer sampling from threshold decisions so truncated
/// frames and invalid dimensions can be characterized without inferring hidden
/// state from the final pass/fail booleans.
class RenderFrameSample {
  final int totalPixels;
  final int readablePixels;
  final int nonBlackPixels;
  final bool centerReadable;

  const RenderFrameSample({
    required this.totalPixels,
    required this.readablePixels,
    required this.nonBlackPixels,
    required this.centerReadable,
  });

  bool get hasCompleteFrame => totalPixels > 0 && readablePixels == totalPixels;

  double get nonBlackRatio =>
      totalPixels == 0 ? 0.0 : nonBlackPixels / totalPixels;
}

/// Replayable counters used by pair validation.
class RenderPairSample {
  final RenderFrameSample frameB;
  final int comparablePixels;
  final int differentPixels;
  final bool hasCompletePair;

  const RenderPairSample({
    required this.frameB,
    required this.comparablePixels,
    required this.differentPixels,
    required this.hasCompletePair,
  });

  double get progressionRatio => frameB.totalPixels == 0 || !hasCompletePair
      ? 0.0
      : differentPixels / frameB.totalPixels;
}

class RenderFrameStats {
  final int centerR;
  final int centerG;
  final int centerB;
  final double nonBlackRatio;
  final bool centerNonBlack;
  final bool histogramSane;

  const RenderFrameStats({
    required this.centerR,
    required this.centerG,
    required this.centerB,
    required this.nonBlackRatio,
    required this.centerNonBlack,
    required this.histogramSane,
  });

  String summary(String backend) {
    return '[renderer] render_frame_stats backend=$backend center=$centerR,$centerG,$centerB non_black_ratio=${nonBlackRatio.toStringAsFixed(4)} histogram_sane=$histogramSane';
  }
}

RenderFrameSample sampleRenderFrame({
  required Uint8List frame,
  required int width,
  required int height,
}) {
  final geometry = _RenderFrameGeometry(width: width, height: height);
  final readablePixels = geometry.readablePixelCount(frame);
  return RenderFrameSample(
    totalPixels: geometry.totalPixels,
    readablePixels: readablePixels,
    nonBlackPixels: _countNonBlackPixels(frame, readablePixels),
    centerReadable: geometry.canReadCenter(frame),
  );
}

RenderCenterSample sampleRenderCenter({
  required Uint8List frame,
  required int width,
  required int height,
}) {
  final geometry = _RenderFrameGeometry(width: width, height: height);
  if (!geometry.canReadCenter(frame)) {
    return const RenderCenterSample.unreadable();
  }

  final cIndex = geometry.centerIndex;
  return RenderCenterSample(
    r: frame[cIndex],
    g: frame[cIndex + 1],
    b: frame[cIndex + 2],
    readable: true,
    nonBlack: _isNonBlack(frame, cIndex),
  );
}

RenderFrameStats validateRenderFrame({
  required Uint8List frame,
  required int width,
  required int height,
}) {
  final sample = sampleRenderFrame(frame: frame, width: width, height: height);
  final center = sampleRenderCenter(
    frame: frame,
    width: width,
    height: height,
  );

  final nonBlackRatio = sample.nonBlackRatio;
  final histogramSane =
      RenderValidationThresholds.defaults.histogramSaneFor(nonBlackRatio);

  return RenderFrameStats(
    centerR: center.r,
    centerG: center.g,
    centerB: center.b,
    nonBlackRatio: nonBlackRatio,
    centerNonBlack: center.nonBlack,
    histogramSane: histogramSane,
  );
}

class RenderCheckResult {
  final int centerR;
  final int centerG;
  final int centerB;
  final double nonBlackRatio;
  final bool centerNonBlack;
  final bool histogramSane;
  final bool frameProgressed;
  final bool iterationDeltaVisible;

  const RenderCheckResult({
    required this.centerR,
    required this.centerG,
    required this.centerB,
    required this.nonBlackRatio,
    required this.centerNonBlack,
    required this.histogramSane,
    required this.frameProgressed,
    required this.iterationDeltaVisible,
  });

  bool get pass =>
      centerNonBlack &&
      histogramSane &&
      frameProgressed &&
      iterationDeltaVisible;

  String summary(String backend) {
    return '[renderer] render_check backend=$backend pass=$pass center=$centerR,$centerG,$centerB non_black_ratio=${nonBlackRatio.toStringAsFixed(4)} frame_progressed=$frameProgressed iter_delta=$iterationDeltaVisible';
  }
}

RenderPairSample sampleRenderPair({
  required Uint8List frameA,
  required Uint8List frameB,
  required int width,
  required int height,
}) {
  final geometry = _RenderFrameGeometry(width: width, height: height);
  final frameBSample = sampleRenderFrame(
    frame: frameB,
    width: width,
    height: height,
  );
  final comparablePixels = math.min(
    geometry.readablePixelCount(frameA),
    frameBSample.readablePixels,
  );
  return RenderPairSample(
    frameB: frameBSample,
    comparablePixels: comparablePixels,
    differentPixels: _countDifferentPixels(
      frameA: frameA,
      frameB: frameB,
      readablePixels: comparablePixels,
    ),
    hasCompletePair:
        geometry.hasCompleteFrame(frameA) && geometry.hasCompleteFrame(frameB),
  );
}

RenderCheckResult validateRenderPair({
  required Uint8List frameA,
  required Uint8List frameB,
  required int width,
  required int height,
}) {
  final sample = sampleRenderPair(
    frameA: frameA,
    frameB: frameB,
    width: width,
    height: height,
  );
  final center = sampleRenderCenter(
    frame: frameB,
    width: width,
    height: height,
  );

  final nonBlackRatio = sample.frameB.nonBlackRatio;
  final histogramSane =
      RenderValidationThresholds.defaults.histogramSaneFor(nonBlackRatio);
  // Progression is a whole-frame claim; a truncated frame can still prove the
  // current histogram, but cannot prove frame-to-frame movement.
  final progressionRatio = sample.progressionRatio;
  final frameProgressed =
      RenderValidationThresholds.defaults.frameProgressedFor(progressionRatio);
  final iterationDeltaVisible = RenderValidationThresholds.defaults
      .iterationDeltaVisibleFor(progressionRatio);

  return RenderCheckResult(
    centerR: center.r,
    centerG: center.g,
    centerB: center.b,
    nonBlackRatio: nonBlackRatio,
    centerNonBlack: center.nonBlack,
    histogramSane: histogramSane,
    frameProgressed: frameProgressed,
    iterationDeltaVisible: iterationDeltaVisible,
  );
}

import 'dart:math';
import 'dart:ui' as ui;

import 'package:flutter/material.dart';
import 'package:flutter_fractals/core/models/fractal_palette.dart';
import 'package:flutter_fractals/core/services/palette_store.dart';

const List<FractalColorStop> _fallbackPaletteStops = [
  FractalColorStop(position: 0.0, colorArgb: 0xFF000000),
  FractalColorStop(position: 1.0, colorArgb: 0xFFFFFFFF),
];

/// Normalizes palette stops before persistence or shader texture/uniform upload.
///
/// The shader texture/uniform paths can carry at most [PaletteService.maxStops]
/// stops, but the bounded list must still span the whole gradient. When an imported
/// palette has too many stops, retain both endpoint colors and drop middle
/// candidates instead of truncating away the final 1.0 stop. A single-color
/// palette is expanded into two endpoint stops so gradient/shader consumers get
/// a replayable span instead of a one-point gradient. Non-finite stop positions
/// are dropped before sorting so malformed stops cannot become endpoint colors.
List<FractalColorStop> normalizePaletteStops(List<FractalColorStop> stops) {
  final finiteStops = _stopsWithFinitePositions(stops);
  if (finiteStops.isEmpty) return _fallbackPaletteStops;

  final sorted = [...finiteStops]
    ..sort((a, b) => a.position.compareTo(b.position));
  final clamped = sorted
      .map((stop) => stop.copyWith(
            position: _clampPaletteStopPosition(stop.position),
          ))
      .toList();

  final bounded = _capPaletteStopsPreservingEndpoint(clamped);
  final normalized = _ensurePaletteEndpointStops(bounded);

  assert(normalized.length >= 2);
  assert(normalized.length <= PaletteService.maxStops);
  assert(normalized.first.position == 0.0);
  assert(normalized.last.position == 1.0);
  return normalized;
}

List<FractalColorStop> _stopsWithFinitePositions(
  List<FractalColorStop> stops,
) {
  return stops.where((stop) => stop.position.isFinite).toList();
}

double _clampPaletteStopPosition(double position) {
  assert(position.isFinite, 'Palette stop position must be finite');
  return position.clamp(0.0, 1.0).toDouble();
}

List<FractalColorStop> _capPaletteStopsPreservingEndpoint(
  List<FractalColorStop> stops,
) {
  assert(stops.isNotEmpty);
  return stops.length > PaletteService.maxStops
      ? [
          ...stops.take(PaletteService.maxStops - 1),
          stops.last,
        ]
      : stops;
}

List<FractalColorStop> _ensurePaletteEndpointStops(
  List<FractalColorStop> stops,
) {
  assert(stops.isNotEmpty);
  if (stops.length == 1) {
    final stop = stops.single;
    return [
      stop.copyWith(position: 0.0),
      stop.copyWith(position: 1.0),
    ];
  }

  return [
    stops.first.copyWith(position: 0.0),
    ...stops.skip(1).take(stops.length - 2),
    stops.last.copyWith(position: 1.0),
  ];
}

String _uniquePaletteId(String requestedId, Set<String> reservedIds) {
  var candidate = requestedId;
  if (!reservedIds.contains(candidate)) return candidate;
  var i = 2;
  while (reservedIds.contains('$candidate-$i')) {
    i++;
  }
  return '$candidate-$i';
}

/// Manages built-in and user-created color palettes.
///
/// Palettes are persisted locally using [PaletteStore].
class PaletteService extends ChangeNotifier {
  static PaletteService? _instance;
  static PaletteService get instance {
    final v = _instance;
    if (v == null) {
      throw StateError('PaletteService not initialized');
    }
    return v;
  }

  static const int maxStops = 8;
  static const int _texWidth = 256;

  final PaletteStore _store;

  /// Cache of palette textures keyed by palette id.
  final Map<String, ui.Image> _paletteTexCache = {};

  late final List<FractalPalette> _builtIn;
  List<FractalPalette> _user = const [];

  PaletteService._(this._store) {
    _builtIn = _createBuiltIns();
  }

  static Future<PaletteService> create({PaletteStore? store}) async {
    final s = store ?? await PaletteStore.create();
    final service = PaletteService._(s);
    await service._load();
    _instance = service;
    return service;
  }

  List<FractalPalette> get builtInPalettes => List.unmodifiable(_builtIn);
  List<FractalPalette> get userPalettes => List.unmodifiable(_user);
  List<FractalPalette> get allPalettes =>
      List.unmodifiable([..._builtIn, ..._user]);

  int get builtInCount => _builtIn.length;

  FractalPalette paletteAtIndex(int index) {
    final all = allPalettes;
    if (all.isEmpty) {
      return FractalPalette(
        id: 'fallback',
        name: 'Fallback',
        stops: _fallbackPaletteStops,
      );
    }
    if (index < 0 || index >= all.length) return all.first;
    return all[index];
  }

  bool isBuiltInIndex(int index) => index >= 0 && index < builtInCount;

  Future<void> addPalette(FractalPalette palette) async {
    await _commitUserPalettes([
      ..._user,
      _prepareNewUserPalette(palette),
    ]);
  }

  Future<void> updatePalette(FractalPalette palette) async {
    await _commitUserPalettes(
      _user
          .map((p) => p.id == palette.id
              ? palette.copyWith(
                  isBuiltIn: false,
                  stops: normalizePaletteStops(palette.stops),
                )
              : p)
          .toList(),
    );
  }

  Future<void> deletePalette(String id) async {
    await _commitUserPalettes(_user.where((p) => p.id != id).toList());
  }

  /// Imports a palette from JSON. If id is missing/duplicate, a new id is generated.
  Future<FractalPalette> importPaletteJson(String input) async {
    final palette = _prepareNewUserPalette(
      FractalPalette.fromJsonString(input),
    );
    await _commitUserPalettes([..._user, palette]);
    return palette;
  }

  String exportPaletteJson(FractalPalette palette, {bool pretty = true}) {
    return palette.copyWith(isBuiltIn: false).toJsonString(pretty: pretty);
  }

  FractalPalette createEmptyPalette({String? name}) {
    final id = _allocateUserPaletteId('');
    return FractalPalette(
      id: id,
      name: name ?? 'Custom Palette',
      stops: _fallbackPaletteStops,
      isBuiltIn: false,
    );
  }

  /// Returns a 256×1 [ui.Image] representing the palette gradient.
  ///
  /// The image is cached per palette id and reused across frames.
  /// Use with `shader.setImageSampler(0, image)` to pass palette as texture.
  ui.Image paletteTexture(FractalPalette palette) {
    final cached = _paletteTexCache[palette.id];
    if (cached != null) return cached;

    final stops = normalizePaletteStops(palette.stops);

    final rec = ui.PictureRecorder();
    final canvas = Canvas(rec, Rect.fromLTWH(0, 0, _texWidth.toDouble(), 1));
    final gradColors = stops.map((s) => Color(s.colorArgb)).toList();
    final gradStops = stops.map((s) => s.position.clamp(0.0, 1.0)).toList();
    final paint = Paint()
      ..shader = ui.Gradient.linear(
        Offset.zero,
        Offset(_texWidth.toDouble(), 0),
        gradColors,
        gradStops,
      );
    canvas.drawRect(Rect.fromLTWH(0, 0, _texWidth.toDouble(), 1), paint);
    final pic = rec.endRecording();
    final img = pic.toImageSync(_texWidth, 1);
    _paletteTexCache[palette.id] = img;
    return img;
  }

  /// Clears cached palette textures (call if palettes change).
  void invalidatePaletteTextures() {
    for (final img in _paletteTexCache.values) {
      img.dispose();
    }
    _paletteTexCache.clear();
  }

  /// Writes custom palette uniforms expected by the shaders.
  ///
  /// Layout:
  /// - [baseIndex + 0] = stopCount
  /// - then 8 vec4 stops, each: r, g, b, position
  void setCustomPaletteUniforms(
    ui.FragmentShader shader,
    int baseIndex,
    FractalPalette palette,
  ) {
    // NOTE: This API is legacy. Prefer setting palette uniforms via a
    // UniformSchema/UniformWriter to avoid hard-coded float indices.

    final stops = normalizePaletteStops(palette.stops);
    final count = stops.length.clamp(0, maxStops);
    shader.setFloat(baseIndex, count.toDouble());

    // Fill remaining with last stop to avoid NaNs in shader.
    final padded = [...stops];
    while (padded.length < maxStops) {
      padded.add(padded.last);
    }

    for (var i = 0; i < maxStops; i++) {
      final s = padded[i];
      final c = Color(s.colorArgb);
      final idx = baseIndex + 1 + i * 4;
      // Flutter 3.19 Color channels are 0-255 ints; normalize to 0.0-1.0.
      shader.setFloat(idx + 0, (c.r * 255.0).round().clamp(0, 255) / 255.0);
      shader.setFloat(idx + 1, (c.g * 255.0).round().clamp(0, 255) / 255.0);
      shader.setFloat(idx + 2, (c.b * 255.0).round().clamp(0, 255) / 255.0);
      shader.setFloat(idx + 3, s.position.clamp(0.0, 1.0));
    }
  }

  Future<void> _commitUserPalettes(List<FractalPalette> palettes) async {
    _user = palettes;
    invalidatePaletteTextures();
    await _store.savePalettes(_user);
    notifyListeners();
  }

  Future<void> _load() async {
    _user = _store
        .loadPalettes()
        .map((p) => p.copyWith(
              stops: normalizePaletteStops(p.stops),
              isBuiltIn: false,
            ))
        .toList();
    invalidatePaletteTextures();
  }

  FractalPalette _prepareNewUserPalette(FractalPalette palette) {
    return palette.copyWith(
      id: _allocateUserPaletteId(palette.id),
      isBuiltIn: false,
      stops: normalizePaletteStops(palette.stops),
    );
  }

  String _allocateUserPaletteId(String requestedId) {
    return _uniquePaletteId(
      requestedId.isEmpty ? _randomId() : requestedId,
      {..._builtIn.map((p) => p.id), ..._user.map((p) => p.id)},
    );
  }

  String _randomId() {
    final r = Random();
    final v = r.nextInt(1 << 32).toRadixString(16).padLeft(8, '0');
    return 'pal_$v';
  }

  static List<FractalPalette> _createBuiltIns() {
    return [
      FractalPalette(
        id: 'builtin_fire',
        name: 'Fire',
        isBuiltIn: true,
        stops: [
          FractalColorStop(position: 0.0, colorArgb: 0xFF0D0D12),
          FractalColorStop(position: 0.35, colorArgb: 0xFF6B1D1D),
          FractalColorStop(position: 0.7, colorArgb: 0xFFF05A28),
          FractalColorStop(position: 1.0, colorArgb: 0xFFFFE066),
        ],
      ),
      FractalPalette(
        id: 'builtin_ocean',
        name: 'Ocean',
        isBuiltIn: true,
        stops: [
          FractalColorStop(position: 0.0, colorArgb: 0xFF06141C),
          FractalColorStop(position: 0.4, colorArgb: 0xFF0B7285),
          FractalColorStop(position: 0.8, colorArgb: 0xFF22B8CF),
          FractalColorStop(position: 1.0, colorArgb: 0xFFA5D8FF),
        ],
      ),
      FractalPalette(
        id: 'builtin_psychedelic',
        name: 'Psychedelic',
        isBuiltIn: true,
